// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import {EfficientHashLib} from "solady/utils/EfficientHashLib.sol";
import {SignatureCheckerLib} from "solady/utils/SignatureCheckerLib.sol";

/**
 * @title Checkpointer
 * @notice Tracks and validates state root checkpoints using EIP-712 signatures from admin and leader nodes.
 * @dev Designed for use in DStack-like distributed settlement systems.
 */
contract Checkpointer {
    /**
     * @notice Address with the authority to set initial parameters.
     * @dev Should be set to the DStack app shared secret public key.
     */
    address public admin;

    /**
     * @notice Public key of the current designated leader node.
     * @dev Leader is responsible for signing and submitting new checkpoints.
     */
    address public leader;

    /**
     * @notice Gnosis Safe address used as the council multisig.
     * @dev Can rotate the leader and self.
     */
    address public councilMultisig;

    /**
     * @notice Monotonically increasing nonce for checkpoint submissions.
     * @dev Used to prevent replay attacks and enforce checkpoint ordering.
     */
    uint256 public stateRootNonce;

    /// @notice Typehash used for EIP-712 encoding of the Checkpoint struct.
    bytes32 public constant CHECKPOINT_TYPEHASH =
        keccak256("Checkpoint(uint256 nonce,uint8[] stateRoot,string[] approvedWithdrawals)");

    /**
     * @notice Emitted when a new list of approved withdrawals is recorded in a checkpoint.
     * @param approvedWithdrawals List of withdrawal IDs approved in the checkpoint.
     */
    event Withdrawals(string[] approvedWithdrawals);

    /// @notice Cached domain separator for EIP-712 signature verification.
    bytes32 internal _domainSeparator;

    /**
     * @notice The current state root, encoded as a serialized vector.
     * @dev Serialized as `(user, eth_balance, usdc_balance, deposit_nonce, is_mm)` tuples.
     *      In production, this may store multiple roots and rotate.
     */
    uint8[] public stateRoot;

    /// @notice Reverts if caller is not the admin.
    error NotAdmin();

    /// @notice Reverts if a value has already been set.
    error AlreadySet();

    /// @notice Reverts if caller is not the current council multisig.
    error NotCouncilMultisig();

    /// @notice Reverts if a signature does not match the expected signer or payload.
    error InvalidSignature();

    /**
     * @notice Contract constructor.
     * @dev Sets the deployer as the initial admin.
     */
    constructor() {
        admin = msg.sender;
    }

    /**
     * @notice Sets the EIP-712 domain separator used for verifying signatures.
     * @param domainSeparator The domain separator to store.
     */
    function setDomainSeparator(bytes32 domainSeparator) external {
        if (msg.sender != admin) revert NotAdmin();
        if (_domainSeparator != 0) revert AlreadySet();
        _domainSeparator = domainSeparator;
    }

    /**
     * @notice Transfers admin control to a new address.
     * @param newAdmin The new admin address.
     */
    function setAdmin(address newAdmin) external {
        if (msg.sender != admin) revert NotAdmin();
        require(newAdmin != address(0));
        admin = newAdmin;
    }

    /**
     * @notice Sets the initial council multisig address.
     * @param newCouncilMultisig The council's Gnosis Safe address.
     */
    function setInitialCouncilMultisig(address newCouncilMultisig) external {
        if (msg.sender != admin) revert NotAdmin();
        if (councilMultisig != address(0)) revert AlreadySet();
        councilMultisig = newCouncilMultisig;
    }

    /**
     * @notice Allows the current council to rotate itself to a new address.
     * @param newCouncilMultisig The new multisig address.
     */
    function setNewCouncilMultisig(address newCouncilMultisig) external {
        if (msg.sender != councilMultisig) revert NotCouncilMultisig();
        councilMultisig = newCouncilMultisig;
    }

    /**
     * @notice Sets the leader node address.
     * @dev This should be reviewed depending on the leader rotation mechanism.
     * @param newLeader The address of the new leader node.
     */
    function setLeader(address newLeader) external {
        if (msg.sender != councilMultisig) revert NotCouncilMultisig();
        leader = newLeader;
    }

    /**
     * @notice Checkpoint submitted by a node to update the system state.
     * @dev Requires valid EIP-712 signatures from both admin and leader.
     * @param sharedSignature Signature by the admin.
     * @param leaderSignature Signature by the leader.
     * @param _checkpoint The checkpoint payload to commit.
     */
    function checkpoint(
        bytes calldata sharedSignature,
        bytes calldata leaderSignature,
        Checkpoint calldata _checkpoint
    ) external {
        require(_checkpoint.nonce == stateRootNonce); // dev: Nonce mismatch

        // Compute the EIP-712 struct hash.
        bytes32 structHash = EfficientHashLib.hash(
            abi.encode(
                CHECKPOINT_TYPEHASH,
                _checkpoint.nonce,
                EfficientHashLib.hash(abi.encodePacked(_checkpoint.stateRoot)),
                hashStringArray(_checkpoint.approvedWithdrawals)
            )
        );

        // Check both admin and leader signatures.
        bytes32 digest =
            EfficientHashLib.hash(abi.encodePacked("\x19\x01", _domainSeparator, structHash));

        if (!SignatureCheckerLib.isValidSignatureNow(admin, digest, sharedSignature)) {
            revert InvalidSignature();
        }

        if (!SignatureCheckerLib.isValidSignatureNow(leader, digest, leaderSignature)) {
            revert InvalidSignature();
        }

        stateRootNonce++;
        stateRoot = _checkpoint.stateRoot;

        emit Withdrawals(_checkpoint.approvedWithdrawals);
    }

    /**
     * @notice Internal helper for hashing an array of strings.
     * @dev Each string is hashed individually and packed before final hashing.
     * @param arr The array of strings to hash.
     * @return A single keccak256 hash of the packed array of hashed strings.
     */
    function hashStringArray(string[] memory arr) internal pure returns (bytes32) {
        bytes32[] memory hashedStrings = new bytes32[](arr.length);
        for (uint256 i = 0; i < arr.length; i++) {
            hashedStrings[i] = EfficientHashLib.hash(bytes(arr[i]));
        }
        return EfficientHashLib.hash(abi.encodePacked(hashedStrings));
    }

    /**
     * @notice Struct defining a checkpoint message.
     * @dev Checkpoints include the current state root, a nonce, and a list of approved withdrawals.
     */
    struct Checkpoint {
        uint256 nonce;
        uint8[] stateRoot;
        string[] approvedWithdrawals;
    }
}

src/CredentialManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import {SignatureCheckerLib} from "solady/utils/SignatureCheckerLib.sol";
import {EfficientHashLib} from "solady/utils/EfficientHashLib.sol";
import {IAdminUpdateStrategy} from "./interfaces/IAdminUpdateStrategy.sol";
import {IAutomataDcapAttestation} from "./interfaces/IAutomataDcapAttestation.sol";

/// @title CredentialManager
/// @notice The centralized Root of Trust for the TEE Clearing Engine.
/// @dev This contract acts as the governance layer and the vault registry. It manages the
///      set of authorized operators, enforces quorum consensus for critical updates, and
///      maintains the registry of deposit vaults across different chains.
///      It combines immediate multi-sig actions for operational tasks with timelocked
///      actions for high-risk configuration changes.
contract CredentialManager {
    using SignatureCheckerLib for address;

    // =============================================================
    //                          STRUCTS
    // =============================================================

    /// @notice Configuration for a specific chain/vault.
    struct ChainConfig {
        uint64 blockTimeMs;
        // Confs
        uint8 defaultConfirmations;
        uint8 depositIngestConfirmations;
        uint8 withdrawalIngestConfirmations;
        uint8 settlementIngestConfirmations;
    }

    /// @notice Represents a deposit vault deployed on a specific chain.
    /// @dev Addresses are stored as bytes32 to support non-EVM chains (e.g., Solana, SVM).
    struct Vault {
        uint8 routingId;
        uint256 vmId; // ChainId for EVM chains.
        /// @notice The address of the vault on that chain (left-aligned or native format).
        bytes32 vaultAddress;
        ChainConfig config;
    }

    /// @notice Tracks the lifecycle state of a timelocked operation.
    struct TimelockOp {
        /// @notice The timestamp (seconds since unix epoch) after which the operation can be executed.
        uint64 eta;
        /// @notice True if the operation has already been executed.
        bool executed;
        /// @notice True if the operation was explicitly canceled by the operators.
        bool canceled;
        /// @notice The type hash of the operation (e.g., OP_SET_RISK_MANAGER) for verification.
        bytes32 opType;
    }

    /// @notice Defines the expected state of the TEE software.
    struct MeasurementProfile {
        bool active; // Is this profile currently allowed?
        bytes32 mrtd; // Mandatory (Code Identity)
        bytes32 rtmr0; // Optional (Set to 0 to skip check)
        bytes32 rtmr1; // Optional
        bytes32 rtmr2; // Optional
        bytes32 rtmr3; // Optional
    }

    struct RestartCandidate {
        address leader;
        uint256 epoch;
        bytes32 checkpointHash;
        bool exists;
    }

    // =============================================================
    //                          ERRORS
    // =============================================================

    /// @notice Thrown when a signature belongs to an address that is not a registered operator.
    /// @param signer The address recovered from the signature.
    error NotOperator(address signer);

    /// @notice Thrown when the provided signatures are not sorted by signer address or contain duplicates.
    /// @dev Signatures must be sorted strictly ascending (A < B) to prevent duplicate counting in O(N).
    error SignersNotSortedOrUnique();

    /// @notice Thrown when the number of valid signatures provided is less than the required threshold.
    /// @param provided The number of signatures provided.
    /// @param required The current `committeeThreshold` required.
    error InsufficientSignatures(uint256 provided, uint256 required);

    /// @notice Thrown when attempting to set a quorum threshold that is 0 or greater than the total operators.
    /// @param newThreshold The proposed threshold.
    /// @param operatorCount The total number of registered operators.
    error InvalidCommitteeThreshold(uint256 newThreshold, uint256 operatorCount);

    /// @notice Thrown when attempting to execute a timelock before the delay has elapsed.
    /// @param opId The unique hash of the operation.
    /// @param readyAt The timestamp when the operation becomes executable.
    /// @param nowTs The current block timestamp.
    error TimelockNotReady(bytes32 opId, uint256 readyAt, uint256 nowTs);

    /// @notice Thrown when attempting to act on a timelock ID that does not exist or was never scheduled.
    /// @param opId The operation hash.
    error TimelockUnknown(bytes32 opId);

    /// @notice Thrown when attempting to execute or schedule an operation that has already been executed.
    /// @param opId The operation hash.
    error TimelockAlreadyExecuted(bytes32 opId);

    /// @notice Thrown when attempting to execute or cancel an operation that has already been canceled.
    /// @param opId The operation hash.
    error TimelockAlreadyCanceled(bytes32 opId);

    /// @notice Thrown when a timelock delay is set to 0 (invalid safety margin).
    /// @param delay The provided delay in seconds.
    error InvalidDelay(uint256 delay);

    /// @notice Thrown when attempting to cancel an operation that cannot be canceled (e.g., already executed).
    error CannotCancel();

    /// @notice Thrown when a critical configuration address (e.g., Risk Manager) is set to address(0).
    error ZeroAddress();

    /// @notice Thrown when a Vault address is empty (bytes32(0)).
    error InvalidVaultAddr();

    /// @notice Thrown when attempting to register a strategy for a chain that already has one.
    error StrategyAlreadyExists();

    /// @notice Thrown when attempting to update vault admins on a chain that has no registered strategy.
    error NoStrategy();

    /// @notice Thrown when a requested vault cannot be found for the specified chain.
    /// @param routingId The routing ID of the vault.
    /// @param vmId The Chain ID for EVM chains requested.
    error VaultNotFound(uint256 routingId, uint256 vmId);

    /// @notice Thrown when the measured TEE state does not match the expected state.
    error MeasurementMismatch(bytes32 expected, bytes32 actual, string field);

    /// @notice Thrown when the ZK Proof attesting measurements is invalid.
    error InvalidZkProof();

    /// @notice Thrown when the supplied epoch is invalid
    error InvalidEpoch(uint256 expected, uint256 actual);
    /// @notice Thrown when a Quote ReportData does not match params.
    error InvalidReportData();
    /// @notice Thrown when a Quote length is invalid.
    error InvalidQuoteLength();
    /// @notice Thrown when a Quote verifier is invalid.
    error InvalidVerifier();
    /// @notice Thrown when the used profile is not active.
    error ProfileInactive(uint256 profileId);
    /// @notice Thrown when the used profile does not exist.
    error InvalidProfileId();
    /// @notice Thrown when the used profile is configured incorrectly.
    error InvalidProfileConfig();

    // Certificate gathering errors
    error GatheringActive();
    error GatheringNotActive();
    error GatheringNotExpired();
    error AmbiguousState();
    error NoCandidate();
    error RestartPendingResolution();
    error ProposedEpochTooLow(uint256 current, uint256 proposed);

    // =============================================================
    //                      CONSTANTS & TYPEHASHES
    // =============================================================

    /// @dev EIP-712 Domain Separator typehash.
    bytes32 private constant _EIP712_DOMAIN_TYPEHASH = keccak256(
        "EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"
    );

    /// @dev EIP-712 name hash for this contract.
    bytes32 private constant _NAME_HASH = keccak256("CredentialManager");

    /// @dev EIP-712 version hash.
    bytes32 private constant _VERSION_HASH = keccak256("1");

    /// @dev Generic Action typehash used for all governance signatures.
    ///      Structure: Action(bytes32 opType, bytes32 paramsHash, uint256 nonce)
    bytes32 private constant _ACTION_TYPEHASH =
        keccak256("Action(bytes32 opType,bytes32 paramsHash,uint256 nonce)");

    /// @dev Used for appointing a leader in the absence of a leader - for bootstrap or emergency recovery.
    bytes32 public constant OP_APPOINT_LEADER = keccak256("OP_APPOINT_LEADER");

    // --- Operation Types (for Signature Verification) ---

    // Immediate Actions (Executed immediately upon valid quorum)
    bytes32 public constant OP_SET_COMMITTEE_THRESHOLD = keccak256("OP_SET_COMMITTEE_THRESHOLD");
    bytes32 public constant OP_ADD_VAULT = keccak256("OP_ADD_VAULT");
    bytes32 public constant OP_REGISTER_STRATEGY = keccak256("OP_REGISTER_ADMIN_UPDATE_STRATEGY");
    bytes32 public constant OP_SET_VAULT_ADMINS = keccak256("OP_SET_DEPOSIT_VAULT_ADMINS");
    bytes32 public constant OP_CANCEL_TIMELOCK = keccak256("OP_CANCEL_TIMELOCK");
    bytes32 public constant OP_WITHDRAW = keccak256("OP_WITHDRAW");

    // Timelocked Actions (Scheduled first, executed later)
    bytes32 public constant OP_SET_RISK_MANAGER = keccak256("OP_SET_RISK_MANAGER");
    bytes32 public constant OP_SET_REGISTRY = keccak256("OP_SET_REGISTRY");
    bytes32 public constant OP_SET_MEASUREMENTS = keccak256("OP_SET_MEASUREMENTS");
    bytes32 public constant OP_SET_DELAY = keccak256("OP_SET_DELAY");
    bytes32 public constant OP_MANAGE_PROFILE = keccak256("OP_MANAGE_PROFILE");

    // Restarts
    bytes32 public constant OP_RESTART = keccak256("OP_RESTART");
    bytes32 public constant OP_SET_AUTOMATA_VERIFIER = keccak256("OP_SET_AUTOMATA_VERIFIER");

    // Certificate gathering
    uint256 public constant GATHERING_DURATION = 1 hours;

    // =============================================================
    //                           STORAGE
    // =============================================================

    // --- Governance State ---

    /// @notice TEMP Admin path, to be revised later.
    address public admin;

    /// @notice The list of authorized Clearing Engine operator addresses (EOAs).
    /// @dev These keys form the root of trust for the system.
    address[] public operators;

    /// @notice Lookup to check if an address is an operator.
    mapping(address => bool) public isOperator;

    /// @notice The minimum number of signatures required to execute a governance action.
    uint256 public committeeThreshold;

    /// @notice A monotonically increasing nonce for governance actions.
    /// @dev Included in every signed hash to strictly order operations and prevent replay attacks.
    uint256 public governanceNonce;

    /// @notice Maps Operator (EOA) -> Attested Key (TEE Address).
    /// @dev Used to verify that a TEE signature belongs to a specific operator.
    mapping(address => bytes32) public operatorToAttestedKey;

    /// @notice The current active leader (Operator Address).
    /// @dev The leader is responsible for coordinating the clearing engine.
    address public leader;

    // --- Execution State (Vault Registry) ---

    /// @notice The registry of all authorized Deposit Vaults.
    /// @dev This list is strictly append-only; vaults cannot be removed to prevent history modification.
    Vault[] public vaults;

    /// @notice Maps a RoutingID to the VMID to the Strategy Contract responsible for sending messages to it.
    /// @dev Used to abstract cross-chain messaging logic (e.g., LayerZero, Optimism Messenger).
    mapping(uint256 => mapping(uint256 => IAdminUpdateStrategy)) public adminUpdateStrategies;

    // --- Configuration ---

    /// @notice The address of the Risk Manager (or multisig) authorized to adjust risk parameters.
    address public riskManager;

    /// @notice The address of the global Registry Contract used for asset/settler configurations.
    address public registryContract;

    // --- Timelock State ---

    /// @notice Configuration mapping for how long specific operations must be delayed.
    /// @dev e.g., OP_SET_REGISTRY -> 72 hours.
    mapping(bytes32 => uint256) public timelockDelayFor;

    /// @notice Stores the status of individual scheduled operations by their hash ID.
    mapping(bytes32 => TimelockOp) public timelockOps;

    // --- TDX measurements ---

    /// @notice The current "Gold Image" measurements required for valid Quotes. Matches based on profile.
    mapping(uint256 => MeasurementProfile) public measurementProfiles;
    uint256 public nextProfileId = 1;

    // --- Restarts ---

    /// @notice Tracks the logical era of the TEE state to prevent replay attacks.
    /// @dev Incremented on every successful restart.
    uint256 public epoch;

    /// @notice The hash of the system state (inventory) associated with the current epoch.
    /// @dev New nodes verify this hash against the leader's data to ensure they are on the correct fork.
    bytes32 public latestCheckpointHash;

    // ZK Verifier Contract (Automata)
    IAutomataDcapAttestation public automataVerifier;

    // --- Certificate gathering ---
    uint256 public restartGatheringDeadline; // 0 = Inactive, >0 = Active
    RestartCandidate public bestCandidate;
    bool public isRestartAmbiguous;

    // =============================================================
    //                           EVENTS
    // =============================================================

    /// @notice Emitted when a new operator is added during initialization.
    event OperatorAdded(address indexed operator);

    /// @notice Emitted when the signature threshold is updated.
    event CommitteeThresholdUpdated(uint256 oldThreshold, uint256 newThreshold);

    /// @notice Emitted when a new vault is added to the registry.
    event VaultAdded(
        uint256 indexed routingId, uint256 indexed vmId, bytes32 vaultAddr, ChainConfig config
    );

    /// @notice Emitted when a new cross-chain strategy is registered.
    event DepositVaultAdministratorsUpdated(
        uint256 indexed routingId,
        uint256 indexed vmId,
        address[] newAdministrators,
        uint256 newWithdrawalQuorum
    );

    /// @notice Emitted when the admin set of a remote vault is updated.
    event DepositVaultAdministratorsUpdated(
        uint256 indexed chainId, address[] newAdministrators, uint256 newWithdrawalQuorum
    );

    /// @notice Emitted when a new cross-chain strategy is registered.
    event AdminUpdateStrategyRegistered(
        uint256 indexed routingId, uint256 indexed vmId, address strategy
    );

    /// @notice Emitted when a new attested key for an operator is registered.
    event AttestedKeyRegistered(address indexed operator, bytes32 indexed newAttestedKey);

    /// @notice Emitted when the quorum leader is updated.
    event LeaderUpdated(address indexed newLeader, bytes32 indexed newAttestedKey);

    // Timelock Events
    event OperationScheduled(bytes32 indexed opId, bytes32 indexed opType, uint256 eta);
    event OperationExecuted(bytes32 indexed opId, bytes32 indexed opType);
    event OperationCanceled(bytes32 indexed opId, bytes32 indexed opType);

    event RiskManagerUpdated(address indexed oldRiskManager, address indexed newRiskManager);
    event RegistryUpdated(address indexed oldRegistry, address indexed newRegistry);
    event TimelockDelayUpdated(bytes32 indexed targetOpType, uint256 oldDelay, uint256 newDelay);

    // Measurement & Restart Events
    /// @notice Emitted when the measurements are updated.
    event MeasurementsUpdated(bytes32 newMrtd, bytes32 newRtmr0);
    event MeasurementProfileUpdated(uint256 indexed profileId, bool active);
    event EpochIncremented(uint256 newEpoch, bytes32 newCheckpointHash);
    event RestartExecuted(address indexed newLeader, uint256 indexed epoch);
    event AutomataVerifierUpdated(address indexed oldVerifier, address indexed newVerifier);

    // Certificate gathering events
    event RestartGatheringStarted(uint256 deadline);
    event RestartCandidateSubmitted(address indexed leader, uint256 epoch, bytes32 checkpointHash);
    event RestartAmbiguityDetected(uint256 epoch, bytes32 hash1, bytes32 hash2);

    // =============================================================
    //                       INITIALIZATION
    // =============================================================

    /// @notice Initializes the Credential Manager with the initial operator set and configuration.
    /// @param initialOperators The list of addresses that will form the initial governance council.
    /// @param initialCommitteeThreshold The number of signatures required for valid governance actions.
    /// @param initialRiskManager The initial Risk Manager address.
    /// @param initialRegistryContract The initial Registry Contract address.
    constructor(
        address[] memory initialOperators,
        uint256 initialCommitteeThreshold,
        address initialRiskManager,
        address initialRegistryContract,
        MeasurementProfile[] memory initialMeasurements,
        address initialAutomataVerifier
    ) {
        admin = msg.sender;

        if (initialRiskManager == address(0)) revert ZeroAddress();
        if (initialRegistryContract == address(0)) revert ZeroAddress();
        automataVerifier = IAutomataDcapAttestation(initialAutomataVerifier);

        _initOperators(initialOperators, initialCommitteeThreshold);

        riskManager = initialRiskManager;
        registryContract = initialRegistryContract;
        // Start IDs at 1 so 0 can be used as a null/sentinel value
        nextProfileId = 1;

        for (uint256 i = 0; i < initialMeasurements.length; i++) {
            MeasurementProfile memory p = initialMeasurements[i];

            // Safety Check: Active profiles must have an MRTD
            if (p.active && p.mrtd == bytes32(0)) revert InvalidProfileConfig();

            measurementProfiles[nextProfileId] = p;
            emit MeasurementProfileUpdated(nextProfileId, p.active);
            nextProfileId++;
        }

        // Default Timelocks
        timelockDelayFor[OP_SET_RISK_MANAGER] = 48 hours;
        timelockDelayFor[OP_SET_REGISTRY] = 72 hours;
        timelockDelayFor[OP_MANAGE_PROFILE] = 7 days;
        timelockDelayFor[OP_SET_DELAY] = 7 days;
    }

    /// @dev Internal helper to process the operator list and set the threshold.
    function _initOperators(address[] memory initialOperators, uint256 initialCommitteeThreshold)
        internal
    {
        uint256 n = initialOperators.length;
        if (n == 0) revert InvalidCommitteeThreshold(initialCommitteeThreshold, 0);
        if (initialCommitteeThreshold == 0 || initialCommitteeThreshold > n) {
            revert InvalidCommitteeThreshold(initialCommitteeThreshold, n);
        }

        for (uint256 i = 0; i < n; i++) {
            address op = initialOperators[i];
            if (op == address(0)) revert ZeroAddress();
            if (isOperator[op]) revert SignersNotSortedOrUnique();
            isOperator[op] = true;
            operators.push(op);
            emit OperatorAdded(op);
        }
        committeeThreshold = initialCommitteeThreshold;
        emit CommitteeThresholdUpdated(0, initialCommitteeThreshold);
    }

    // =============================================================
    //                  QUORUM & KEYS
    // =============================================================

    /// @notice Allows an operator to register their TEE's attested key.
    /// @dev Maps the attested_pubkey of a new CE joining the quorum.
    /// @param newAttestedKey The address derived from the TEE's public key.
    function registerAttestedKey(bytes32 newAttestedKey) external {
        if (!isOperator[msg.sender]) revert NotOperator(msg.sender);
        if (newAttestedKey == bytes32(0)) revert ZeroAddress();

        operatorToAttestedKey[msg.sender] = newAttestedKey;
        emit AttestedKeyRegistered(msg.sender, newAttestedKey);
    }

    /// @notice Returns the full Committee configuration.
    /// @dev Let's operators query for 'k (the committee threshold), n' thresholds and the current committee member list".
    function getCommitteeConfig()
        external
        view
        returns (address[] memory members, uint256 k, uint256 n)
    {
        return (operators, committeeThreshold, operators.length);
    }

    /// @notice Returns the current Leader's Operator Address and Attested Key.
    /// @dev When querying current leader, then the contract returns the active operator_pubkey and attested_pubkey.
    function getLeader() external view returns (address operator, bytes32 attestedKey) {
        return (leader, operatorToAttestedKey[leader]);
    }

    /// @dev Internal helper to update mappings.
    function _setAttestedKey(address op, bytes32 attKey) internal {
        operatorToAttestedKey[op] = attKey;
        emit AttestedKeyRegistered(op, attKey);
    }

    /// @dev Builds the administrator list from operator-attested keys.
    function _getAttestedAdministrators() internal view returns (address[] memory admins) {
        uint256 len = operators.length;
        admins = new address[](len);
        for (uint256 i = 0; i < len; i++) {
            bytes32 attKey = operatorToAttestedKey[operators[i]];
            if (attKey == bytes32(0)) revert ZeroAddress();
            admins[i] = address(uint160(uint256(attKey)));
        }
    }

    /// @dev Internal helper to rotate the leader for use in restarts.
    function _updateLeader(address newLeader) internal {
        if (!isOperator[newLeader]) revert NotOperator(newLeader);
        // Check bytes32 zero
        if (operatorToAttestedKey[newLeader] == bytes32(0)) revert ZeroAddress();
        leader = newLeader;

        emit LeaderUpdated(newLeader, operatorToAttestedKey[newLeader]);
    }

    /// @notice Manually appoints a leader. Used for bootstrapping or emergency recovery.
    function appointLeader(
        address newLeader,
        address[] calldata signers,
        bytes[] calldata signatures
    ) external {
        if (!isOperator[newLeader]) revert NotOperator(newLeader);

        // Leader MUST have a registered key, or they cannot sign Attestations/Checkpoints
        if (operatorToAttestedKey[newLeader] == bytes32(0)) revert ZeroAddress();

        bytes32 paramsHash = keccak256(abi.encode(newLeader));
        _requireCommitteeApproval(OP_APPOINT_LEADER, paramsHash, signers, signatures);

        _updateLeader(newLeader);
    }

    // =============================================================
    //          RESTART CERTIFICATION & CERTIFICATE GATHERING
    // =============================================================

    /// @notice Step 1: Initiates the gathering window if the system is down.
    function initiateRestart() external {
        if (restartGatheringDeadline > block.timestamp) revert GatheringActive();
        bool hasResolvablePendingCandidate = bestCandidate.exists && !isRestartAmbiguous
            && isOperator[bestCandidate.leader]
            && operatorToAttestedKey[bestCandidate.leader] != bytes32(0);
        if (
            restartGatheringDeadline != 0 && block.timestamp >= restartGatheringDeadline
                && hasResolvablePendingCandidate
        ) {
            revert RestartPendingResolution();
        }

        // Start 1 hour window
        restartGatheringDeadline = block.timestamp + GATHERING_DURATION;

        // Clear previous state
        delete bestCandidate;
        isRestartAmbiguous = false;

        emit RestartGatheringStarted(restartGatheringDeadline);
    }

    /// @notice Restarts the system using a Trustless ZK Proof (Automata / SP1). The contract stores the "Best" candidate.
    /// @dev We compare Epochs. The highest epoch wins.
    /// @param tdxReportBody The 'Public Output' of the ZK Circuit (The TEE Quote Body).
    /// @param zkProof The Groth16 proof bytes.
    /// @param newLeader The address claiming leadership.
    /// @param checkpointHash The state hash being served.
    function submitRestartProof(
        uint256 profileId,
        bytes calldata tdxReportBody,
        bytes calldata zkProof,
        address newLeader,
        bytes32 checkpointHash
    ) external {
        if (restartGatheringDeadline == 0 || block.timestamp > restartGatheringDeadline) {
            revert GatheringNotActive();
        }
        if (newLeader == address(0)) revert ZeroAddress();
        if (address(automataVerifier) == address(0)) revert InvalidVerifier();

        // 1. ZK Verification
        // Assert that the 'tdxReportBody' was indeed generated by a genuine Intel TDX hardware
        // running the code logic proved by the ZK circuit.
        (bool success, bytes memory errorData) = automataVerifier.verifyAndAttestWithZKProof(
            tdxReportBody,
            IAutomataDcapAttestation.ZkCoProcessorType.Succinct, // Opinionated: Use SP1
            zkProof
        );

        // Handle failure explicitly
        if (!success) {
            // Forward the error from Automata if possible, or generic revert
            if (errorData.length > 0) {
                assembly {
                    let retLen := mload(errorData)
                    revert(add(32, errorData), retLen)
                }
            } else {
                revert InvalidZkProof();
            }
        }

        // 2. Policy Check (The "Gold Image")
        // Verify that the Code Hash (MRTD) inside the verified body matches our governance.
        // MRTD is at offset 136. We take the first 32 bytes of the SHA384.
        if (tdxReportBody.length < 584) revert InvalidQuoteLength();
        bytes32 qMrtd = bytes32(tdxReportBody[136:168]);

        // RTMRs start at 328. Stride is 48 bytes.
        bytes32 qRtmr0 = bytes32(tdxReportBody[328:360]);
        bytes32 qRtmr1 = bytes32(tdxReportBody[376:408]);
        bytes32 qRtmr2 = bytes32(tdxReportBody[424:456]);
        bytes32 qRtmr3 = bytes32(tdxReportBody[472:504]);

        verifyMeasurements(profileId, qMrtd, qRtmr0, qRtmr1, qRtmr2, qRtmr3);

        // 3. Identity Binding
        // Verify that the TEE explicitly committed to this Leader and Checkpoint in ReportData.
        // [Leader (20) | Checkpoint (32) | Epoch (8) | ProcessedCount (4)]
        // Total 64 bytes at Offset 520
        // A. Extract Leader (Bytes 520..540)
        address recoveredLeader = address(bytes20(tdxReportBody[520:540]));

        // B. Extract Checkpoint (Bytes 540..572)
        bytes32 recoveredCheckpoint = bytes32(tdxReportBody[540:572]);

        // C. Extract Epoch (Bytes 572..580)
        // We read 8 bytes, cast to uint64.
        uint64 recoveredEpoch = uint64(bytes8(tdxReportBody[572:580]));

        if (recoveredLeader != newLeader) revert InvalidReportData();
        if (recoveredCheckpoint != checkpointHash) revert InvalidReportData();

        // 5. Monotonicity Check
        if (recoveredEpoch <= epoch) {
            revert ProposedEpochTooLow(epoch, recoveredEpoch);
        }

        // If this is the first valid candidate
        if (!bestCandidate.exists) {
            bestCandidate = RestartCandidate({
                leader: newLeader,
                epoch: recoveredEpoch,
                checkpointHash: checkpointHash,
                exists: true
            });
            emit RestartCandidateSubmitted(newLeader, recoveredEpoch, checkpointHash);
            return;
        }

        // If we already have a candidate, COMPARE.

        // Case 1: Proposed Epoch is HIGHER -> Replace Best
        if (recoveredEpoch > bestCandidate.epoch) {
            // Strictly better epoch -> Replace
            bestCandidate = RestartCandidate({
                leader: newLeader,
                epoch: recoveredEpoch,
                checkpointHash: checkpointHash,
                exists: true
            });
            isRestartAmbiguous = false;
            emit RestartCandidateSubmitted(newLeader, recoveredEpoch, checkpointHash);
        }
        // Case 2: Proposed Epoch is EQUAL
        else if (recoveredEpoch == bestCandidate.epoch) {
            // If Hash is DIFFERENT -> SPLIT BRAIN
            if (checkpointHash != bestCandidate.checkpointHash) {
                isRestartAmbiguous = true;
                emit RestartAmbiguityDetected(
                    recoveredEpoch, bestCandidate.checkpointHash, checkpointHash
                );
            }
            // If Hash is SAME, ignore (duplicate proposal)
        }
        // Case 3: Proposed Epoch is LOWER -> Ignore
    }

    /// @notice Step 3: Finalizes the restart after the window closes.
    function resolveRestart() external {
        if (restartGatheringDeadline == 0) revert GatheringNotActive();
        if (block.timestamp <= restartGatheringDeadline) revert GatheringNotExpired();

        if (!bestCandidate.exists) revert NoCandidate();
        if (isRestartAmbiguous) revert AmbiguousState();

        // Apply State
        _updateLeader(bestCandidate.leader);
        latestCheckpointHash = bestCandidate.checkpointHash;
        epoch = bestCandidate.epoch;

        // Reset Gathering
        restartGatheringDeadline = 0;
        delete bestCandidate;

        emit EpochIncremented(epoch, latestCheckpointHash);
        emit RestartExecuted(leader, epoch);
    }

    // =============================================================
    //                     GOVERNANCE VERIFICATION
    // =============================================================

    /// @notice Returns the EIP-712 domain separator used for verifying governance signatures.
    /// @return The domain separator hash.
    function domainSeparator() public view returns (bytes32) {
        return keccak256(
            abi.encode(
                _EIP712_DOMAIN_TYPEHASH, _NAME_HASH, _VERSION_HASH, block.chainid, address(this)
            )
        );
    }

    /// @dev Reconstructs the signed EIP-712 digest for a specific action.
    function _hashAction(bytes32 opType, bytes32 paramsHash, uint256 nonce)
        internal
        view
        returns (bytes32)
    {
        bytes32 structHash = keccak256(abi.encode(_ACTION_TYPEHASH, opType, paramsHash, nonce));
        return keccak256(abi.encodePacked("\x19\x01", domainSeparator(), structHash));
    }

    /// @notice Verifies that a payload has been signed by a valid quorum of operators.
    /// @dev This is the core access control modifier. It verifies:
    ///      1. Sufficient signatures (k of n).
    ///      2. Signers are valid operators.
    ///      3. Signatures are unique and sorted (to prevent duplicates).
    ///      4. The payload matches the expected operation type and parameters.
    ///      5. Increments the nonce to prevent replay attacks.
    /// @param opType The operation identifier (e.g., OP_ADD_VAULT).
    /// @param paramsHash The keccak256 hash of the abi-encoded parameters.
    /// @param signers An array of operator addresses who signed the payload. Must be sorted ascending.
    /// @param signatures An array of signatures corresponding to the signers.
    function _requireCommitteeApproval(
        bytes32 opType,
        bytes32 paramsHash,
        address[] calldata signers,
        bytes[] calldata signatures
    ) internal {
        // If sender is admin and no signatures provided, skip verification.
        if (msg.sender == admin && signers.length == 0 && signatures.length == 0) {
            // Increment nonce anyway to simulate state change/prevent strict replays
            unchecked {
                governanceNonce++;
            }
            return;
        }
        uint256 q = committeeThreshold;
        if (signers.length != signatures.length) revert SignersNotSortedOrUnique();
        if (signers.length < q || signatures.length < q) {
            revert InsufficientSignatures(signers.length, q);
        }

        bytes32 digest = _hashAction(opType, paramsHash, governanceNonce);

        address prev = address(0);
        for (uint256 i = 0; i < q; i++) {
            address signer = signers[i];
            // Enforce sorted order to check for duplicates (O(N) vs O(N^2))
            if (signer <= prev) revert SignersNotSortedOrUnique();
            prev = signer;

            if (!isOperator[signer]) revert NotOperator(signer);

            // Handles EIP-1271 and EOA signatures.
            if (!signer.isValidSignatureNow(digest, signatures[i])) revert NotOperator(signer);
        }

        // Increment nonce to invalidate this hash for future use
        unchecked {
            governanceNonce++;
        }
    }

    // =============================================================
    //                  IMMEDIATE ACTIONS
    // =============================================================

    /// @notice Updates the number of signatures required for valid governance actions.
    /// @dev Requires a quorum of the *current* operators to approve.
    /// @param newThreshold The new minimum number of signatures.
    /// @param signers Sorted array of signers.
    /// @param signatures Corresponding signatures.
    function updateCommitteeThreshold(
        uint256 newThreshold,
        address[] calldata signers,
        bytes[] calldata signatures
    ) external {
        if (newThreshold == 0 || newThreshold > operators.length) {
            revert InvalidCommitteeThreshold(newThreshold, operators.length);
        }

        bytes32 paramsHash = keccak256(abi.encode(newThreshold));
        _requireCommitteeApproval(OP_SET_COMMITTEE_THRESHOLD, paramsHash, signers, signatures);

        uint256 oldThreshold = committeeThreshold;
        committeeThreshold = newThreshold;

        emit CommitteeThresholdUpdated(oldThreshold, newThreshold);
    }

    /// @notice Registers a new deposit vault to the system.
    /// @dev This list is append-only. New vaults can be added, but existing ones cannot be removed.
    /// @param routingId The routing ID of the vault.
    /// @param vmId The Chain ID for EVM chains requested.
    /// @param vaultAddr The address of the vault (as bytes32).
    /// @param signers Sorted array of signers.
    /// @param signatures Corresponding signatures.
    function addVault(
        uint8 routingId,
        uint256 vmId,
        bytes32 vaultAddr,
        ChainConfig calldata config,
        address[] calldata signers,
        bytes[] calldata signatures
    ) external {
        if (vaultAddr == bytes32(0)) revert InvalidVaultAddr();

        bytes32 paramsHash = keccak256(abi.encode(routingId, vmId, vaultAddr, config));
        _requireCommitteeApproval(OP_ADD_VAULT, paramsHash, signers, signatures);

        vaults.push(
            Vault({routingId: routingId, vmId: vmId, vaultAddress: vaultAddr, config: config})
        );
        emit VaultAdded(routingId, vmId, vaultAddr, config);
    }

    /// @notice Registers a strategy contract to handle updates for a specific chain.
    /// @dev Used to define how the Credential Manager talks to L2s (e.g., via bridges).
    ///      Only one strategy can be registered per chain.
    /// @param routingId The routing ID of the vault.
    /// @param vmId The Chain ID for EVM chains requested.
    /// @param strategy The address of the strategy contract.
    /// @param signers Sorted array of signers.
    /// @param signatures Corresponding signatures.
    function registerAdminUpdateStrategy(
        uint8 routingId,
        uint256 vmId,
        IAdminUpdateStrategy strategy,
        address[] calldata signers,
        bytes[] calldata signatures
    ) external {
        if (address(strategy) == address(0)) revert ZeroAddress();
        if (address(adminUpdateStrategies[routingId][vmId]) != address(0)) {
            revert StrategyAlreadyExists();
        }

        bytes32 paramsHash = keccak256(abi.encode(routingId, vmId, address(strategy)));
        _requireCommitteeApproval(OP_REGISTER_STRATEGY, paramsHash, signers, signatures);

        adminUpdateStrategies[routingId][vmId] = strategy;
        emit AdminUpdateStrategyRegistered(routingId, vmId, address(strategy));
    }

    /// @notice Updates the administrators or withdrawal quorum for a vault on a remote chain.
    /// @dev Admin can set arbitrary administrators/quorum using the debug path.
    ///      Non-admin calls ignore the provided administrators/quorum and instead sync administrators
    ///      from operator-attested keys, using the current committee threshold as the quorum.
    /// @param routingId The routing ID of the vault.
    /// @param vmId The Chain ID for EVM chains requested.
    /// @param newAdministrators The list of new admin addresses for that vault.
    /// @param newWithdrawalQuorum The new quorum requirement for that vault.
    function setDepositVaultAdministrators(
        uint256 routingId,
        uint256 vmId,
        address[] calldata newAdministrators,
        uint256 newWithdrawalQuorum
    ) external payable {
        IAdminUpdateStrategy strategy = adminUpdateStrategies[routingId][vmId];
        if (address(strategy) == address(0)) revert NoStrategy();

        address[] memory admins;
        uint256 withdrawalQuorum;
        if (msg.sender == admin) {
            admins = newAdministrators;
            withdrawalQuorum = newWithdrawalQuorum;
        } else {
            admins = _getAttestedAdministrators();
            withdrawalQuorum = committeeThreshold;
        }

        // Delegatecall allows this contract to retain its identity (msg.sender) when calling the bridge.
        (bool ok,) = address(strategy)
            .delegatecall(
                abi.encodeWithSelector(
                    strategy.setAdministrators.selector,
                    _getVaultAddress(routingId, vmId),
                    admins,
                    withdrawalQuorum
                )
            );
        require(ok, "Strategy delegatecall failed");
        emit DepositVaultAdministratorsUpdated(routingId, vmId, admins, withdrawalQuorum);
    }

    /// @notice Withdraw funds held by this contract.
    /// @param account Recipient of withdrawn ETH.
    /// @param amount Exact ETH amount authorized by committee signatures.
    function withdraw(
        address account,
        uint256 amount,
        address[] calldata signers,
        bytes[] calldata signatures
    ) external {
        if (account == address(0)) revert ZeroAddress();
        bytes32 paramsHash = keccak256(abi.encode(account, amount));
        _requireCommitteeApproval(OP_WITHDRAW, paramsHash, signers, signatures);
        payable(account).transfer(amount);
    }

    // =============================================================
    //                     VIEW HELPERS
    // =============================================================

    /// @notice Returns a paginated list of registered vaults.
    /// @dev The input types are intentionally `uint16` to preserve the function selector
    ///      `0x9fd7285c` for backward compatibility with existing Rust clients.
    /// @param start The start index.
    /// @param end The end index (exclusive).
    /// @return An array of Vault structs.
    function getVaults(uint16 start, uint16 end) external view returns (Vault[] memory) {
        uint256 count = vaults.length;
        if (start >= count) return new Vault[](0);
        if (end > count) end = uint16(count);
        if (end <= start) return new Vault[](0);

        uint256 len = uint256(end - start);
        Vault[] memory out = new Vault[](len);
        for (uint256 i = 0; i < len; i++) {
            out[i] = vaults[uint256(start) + i];
        }
        return out;
    }

    function _getVaultAddress(uint256 routingId, uint256 vmId) internal view returns (address) {
        uint256 len = vaults.length;
        for (uint256 i; i < len; ++i) {
            Vault memory vault = vaults[i];
            if (vault.routingId == routingId && vault.vmId == vmId) {
                // Convert bytes32 to address (assuming left-aligned or standard encoding).
                // Shifts right 96 bits to recover the 160-bit address if it was stored left-aligned.
                return address(uint160(uint256(vault.vaultAddress >> 96)));
            }
        }
        revert VaultNotFound(routingId, vmId);
    }

    // =============================================================
    //                  TIMELOCKED ACTIONS
    // =============================================================

    /// @notice Schedules a timelocked update for the Risk Manager address.
    /// @dev The operation cannot be executed until `TIMELOCK_DELAY` has passed.
    /// @param newRiskManager The proposed new Risk Manager address.
    /// @return opId The unique hash of the scheduled operation.
    function scheduleRiskManager(
        address newRiskManager,
        address[] calldata signers,
        bytes[] calldata signatures
    ) external returns (bytes32 opId) {
        if (newRiskManager == address(0)) revert ZeroAddress();
        bytes32 paramsHash = keccak256(abi.encode(newRiskManager));
        _requireCommitteeApproval(OP_SET_RISK_MANAGER, paramsHash, signers, signatures);
        opId = _schedule(OP_SET_RISK_MANAGER, paramsHash);
    }

    /// @notice Executes a pending Risk Manager update if the timelock has expired.
    /// @param newRiskManager The address that was previously scheduled.
    function executeRiskManager(address newRiskManager) external {
        if (newRiskManager == address(0)) revert ZeroAddress();
        bytes32 paramsHash = keccak256(abi.encode(newRiskManager));
        bytes32 opId = _opId(OP_SET_RISK_MANAGER, paramsHash);

        _executeTimelock(opId);

        address old = riskManager;
        riskManager = newRiskManager;
        emit OperationExecuted(opId, OP_SET_RISK_MANAGER);
        emit RiskManagerUpdated(old, newRiskManager);
    }

    /// @notice Schedules a timelocked update for the Registry Contract address.
    /// @param newRegistry The proposed new Registry address.
    /// @return opId The unique hash of the scheduled operation.
    function scheduleRegistryContract(
        address newRegistry,
        address[] calldata signers,
        bytes[] calldata signatures
    ) external returns (bytes32 opId) {
        if (newRegistry == address(0)) revert ZeroAddress();
        bytes32 paramsHash = keccak256(abi.encode(newRegistry));
        _requireCommitteeApproval(OP_SET_REGISTRY, paramsHash, signers, signatures);
        opId = _schedule(OP_SET_REGISTRY, paramsHash);
    }

    /// @notice Executes a pending Registry Contract update if the timelock has expired.
    /// @param newRegistry The address that was previously scheduled.
    function executeRegistryContract(address newRegistry) external {
        if (newRegistry == address(0)) revert ZeroAddress();
        bytes32 paramsHash = keccak256(abi.encode(newRegistry));
        bytes32 opId = _opId(OP_SET_REGISTRY, paramsHash);

        _executeTimelock(opId);

        address old = registryContract;
        registryContract = newRegistry;
        emit OperationExecuted(opId, OP_SET_REGISTRY);
        emit RegistryUpdated(old, newRegistry);
    }

    // Timelocked measurement actions

    /// @notice Validates measurements against a specific approved Profile.
    /// @dev Supports "Partial Matching": If the Profile has bytes32(0) for an RTMR,
    ///      skips checking that specific register (accommodating different provider patterns).
    function verifyMeasurements(
        uint256 profileId,
        bytes32 checkMrtd,
        bytes32 checkRtmr0,
        bytes32 checkRtmr1,
        bytes32 checkRtmr2,
        bytes32 checkRtmr3
    ) internal view {
        MeasurementProfile memory profile = measurementProfiles[profileId];

        if (!profile.active) revert ProfileInactive(profileId);
        if (profile.mrtd == bytes32(0)) revert ZeroAddress();

        // MRTD is always mandatory
        if (checkMrtd != profile.mrtd) revert MeasurementMismatch(profile.mrtd, checkMrtd, "MRTD");

        // RTMRs are conditional based on the Profile configuration
        if (profile.rtmr0 != bytes32(0) && checkRtmr0 != profile.rtmr0) {
            revert MeasurementMismatch(profile.rtmr0, checkRtmr0, "RTMR0");
        }

        if (profile.rtmr1 != bytes32(0) && checkRtmr1 != profile.rtmr1) {
            revert MeasurementMismatch(profile.rtmr1, checkRtmr1, "RTMR1");
        }

        if (profile.rtmr2 != bytes32(0) && checkRtmr2 != profile.rtmr2) {
            revert MeasurementMismatch(profile.rtmr2, checkRtmr2, "RTMR2");
        }

        if (profile.rtmr3 != bytes32(0) && checkRtmr3 != profile.rtmr3) {
            revert MeasurementMismatch(profile.rtmr3, checkRtmr3, "RTMR3");
        }
    }

    /// @notice Governance proposes adding or updating a measurement profile (e.g., for Phala or GCP).
    function scheduleManageProfile(
        uint256 profileId,
        MeasurementProfile calldata profile,
        address[] calldata signers,
        bytes[] calldata signatures
    ) external returns (bytes32 opId) {
        // Anti-Bricking: MRTD must never be zero if activating
        if (profile.active && profile.mrtd == bytes32(0)) revert InvalidVaultAddr();

        bytes32 paramsHash = keccak256(abi.encode(profileId, profile));
        _requireCommitteeApproval(OP_MANAGE_PROFILE, paramsHash, signers, signatures);
        opId = _schedule(OP_MANAGE_PROFILE, paramsHash);
    }

    function executeManageProfile(uint256 profileId, MeasurementProfile calldata profile) external {
        bytes32 paramsHash = keccak256(abi.encode(profileId, profile));
        bytes32 opId = _opId(OP_MANAGE_PROFILE, paramsHash);

        _executeTimelock(opId);

        // Auto-increment ID if adding a new one with ID 0
        uint256 idToUpdate = profileId;
        if (idToUpdate == 0) {
            idToUpdate = nextProfileId++;
        }

        measurementProfiles[idToUpdate] = profile;
        emit OperationExecuted(opId, OP_MANAGE_PROFILE);
        emit MeasurementProfileUpdated(idToUpdate, profile.active);
    }

    /// @notice Sxecudes a timelocked update for the Automata Verifier address.
    function executeUpdateAutomataVerifier(address newVerifier) external {
        if (newVerifier == address(0)) revert ZeroAddress();
        bytes32 paramsHash = keccak256(abi.encode(newVerifier));
        bytes32 opId = _opId(OP_SET_AUTOMATA_VERIFIER, paramsHash);
        _executeTimelock(opId);

        address old = address(automataVerifier);
        automataVerifier = IAutomataDcapAttestation(newVerifier);

        emit OperationExecuted(opId, OP_SET_AUTOMATA_VERIFIER);
        emit AutomataVerifierUpdated(old, newVerifier);
    }

    /// @notice Schedules a timelocked update for the Automata Verifier.
    /// @dev Operators vote to update the verifier and the update is proposed with a timelocked delay.
    function scheduleUpdateAutomataVerifier(
        address newVerifier,
        address[] calldata signers,
        bytes[] calldata signatures
    ) external returns (bytes32 opId) {
        if (newVerifier == address(0)) revert ZeroAddress();
        bytes32 paramsHash = keccak256(abi.encode(newVerifier));
        _requireCommitteeApproval(OP_SET_AUTOMATA_VERIFIER, paramsHash, signers, signatures);
        opId = _schedule(OP_SET_AUTOMATA_VERIFIER, paramsHash);
    }

    // Timelock cancellation

    /// @notice Cancels a pending timelocked operation.
    /// @dev Can be called at any time before execution to prevent a malicious or erroneous update.
    /// @param opId The hash of the operation to cancel.
    function cancelTimelock(bytes32 opId, address[] calldata signers, bytes[] calldata signatures)
        external
    {
        bytes32 paramsHash = keccak256(abi.encode(opId));
        _requireCommitteeApproval(OP_CANCEL_TIMELOCK, paramsHash, signers, signatures);

        TimelockOp storage op = timelockOps[opId];
        if (op.eta == 0) revert TimelockUnknown(opId);
        if (op.executed) revert TimelockAlreadyExecuted(opId);
        if (op.canceled) revert TimelockAlreadyCanceled(opId);

        op.canceled = true;
        emit OperationCanceled(opId, op.opType);
    }

    // =============================================================
    //                     TIMELOCK INTERNAL LOGIC
    // =============================================================

    /// @dev Deterministically generates the operation ID hash.
    function _opId(bytes32 opType, bytes32 paramsHash) internal view returns (bytes32) {
        return keccak256(abi.encode(opType, paramsHash, address(this), block.chainid));
    }

    /// @dev Internal helper to schedule an operation.
    function _schedule(bytes32 opType, bytes32 paramsHash) internal returns (bytes32 opId) {
        opId = _opId(opType, paramsHash);
        TimelockOp storage op = timelockOps[opId];
        if (op.executed) revert TimelockAlreadyExecuted(opId);

        uint256 delay = timelockDelayFor[opType];
        if (delay == 0) revert InvalidDelay(delay);

        uint64 eta = uint64(block.timestamp + delay);
        op.eta = eta;
        op.executed = false;
        op.canceled = false;
        op.opType = opType;
        emit OperationScheduled(opId, opType, eta);
    }

    /// @dev Internal helper to validate if an operation is ready for execution.
    function _executeTimelock(bytes32 opId) internal {
        TimelockOp storage op = timelockOps[opId];
        if (op.eta == 0) revert TimelockUnknown(opId);
        if (op.executed) revert TimelockAlreadyExecuted(opId);
        if (op.canceled) revert TimelockAlreadyCanceled(opId);
        if (block.timestamp < op.eta) revert TimelockNotReady(opId, op.eta, block.timestamp);
        op.executed = true;
    }

    /// @notice Allows the contract to receive ETH (needed for strategies that require fees).
    receive() external payable {}
}

src/DepositVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import {SafeTransferLib} from "solady/utils/SafeTransferLib.sol";
import {EfficientHashLib} from "solady/utils/EfficientHashLib.sol";
import {ECDSA} from "solady/utils/ECDSA.sol";
import {IAtomicSettlementCallback} from "./interfaces/IAtomicSettlementCallback.sol";

contract DepositVault {
    /// @notice The number of decimals used by the clearing engine for normalized amounts.
    /// @dev Must stay in sync with the clearing engine's normalization logic.
    uint8 internal constant CLEARING_ENGINE_DECIMALS = 18;

    /**
     * @notice The admin approves settlements and withdrawals.
     * @dev Should be set to the DStack container shared secret address.
     */
    address public owner;

    /**
     * @notice The address responsible for adding or removing administrators
     * @dev In production, this will be an upgradeable proxy
     */
    address public credentialManager;

    /// @notice Domain separator used for signature verification. It should include the routing ID, the vm ID, this
    /// vault address, and the settlement schema version.
    bytes32 internal _domainSeparator;

    /// @notice Maps settler IDs to their executor addresses.
    mapping(bytes32 => SettlerInfo) settlerExecutorMap;

    /// @notice List of all approved settler IDs.
    bytes32[] public approvedSettlers;

    /// @notice Minimum number of administrator signatures to approve a withdrawal request
    uint256 public withdrawalQuorum;

    uint256 public credentialManagerChangeDelayBlocks = 14400;

    /// @notice Tracks which settler IDs have been approved.
    mapping(bytes32 => bool) internal settlerIsApproved;

    /**
     * @notice Maximum total tokens that can be settled in a single block for each token.
     * @dev Currently unused — implementation pending design finalization.
     */
    mapping(address => uint256) public settlementCaps;

    /// @notice Maps (settler ID, account_index) pairs to their queue of pending batch settlements.
    mapping(bytes32 => mapping(uint64 => PendingSettlement[])) public pendingSettlements;

    /// @notice Maps (settler ID, account_index) pairs to their settlement count (nonce).
    mapping(bytes32 => mapping(uint64 => uint64)) public settlementCounts;

    /// @notice Maps user ID pairs to their deposit count (nonce).
    mapping(bytes32 => uint64) public depositCounts;

    /// @notice Maps user ID to their withdrawal count (nonce).
    mapping(bytes32 => uint64) public withdrawalCounts;

    /// @notice Set of administrators
    address[] public administrators;

    // TODO: Delete before official production.
    mapping(address => bool) public canDeposit;

    /// @notice Block number of latest signature use
    uint256 public lastSignatureUse;

    /**
     * Makes the signature unambiguous that it is for settlements.
     */
    bytes32 public constant SETTLEMENT_TYPEHASH = keccak256("SettlementApprovalV1");

    /**
     * Makes the signature unambiguous that it is for withdrawals.
     */
    bytes32 constant WITHDRAWAL_TYPEHASH = keccak256("WithdrawalApprovalV1");

    /// @notice Request for settlement
    /// @dev Used for all forms of settlement supported by the t+ vault
    struct Settlement {
        /// @notice Address of the token to be sent OUT from the vault
        address tokenOut;
        /// @notice Quantity of the output token to be sent OUT from the vault
        uint256 amountOut;
        /// @notice Address of the token to be sent IN to the vault
        address tokenIn;
        /// @notice Quantity of the input token to be sent IN from the vault
        uint256 amountIn;
        /// @notice Unique identifier of the user being settled
        bytes32 user;
        /// @notice Account index of the user being settled
        uint64 account;
        /// @notice Settlement nonce for this request
        uint256 nonce;
        /// @notice Timestamp at which this request is valid until (i.e.,
        ///         immediately after this time this request is considered
        ///         expired)
        uint256 validUntil;
    }

    /// @notice Request for settlement
    /// @dev Used for all forms of settlement supported by the t+ vault
    struct SettlementOrder {
        /// @notice Address of the token to be sent OUT from the vault
        address tokenOut;
        /// @notice Quantity of the output token to be sent OUT from the vault
        uint256 amountOut;
        /// @notice Address of the token to be sent IN to the vault
        address tokenIn;
        /// @notice Quantity of the input token to be sent IN from the vault
        uint256 amountIn;
        /// @notice Settlement nonce for this request
        uint256 nonce;
    }

    /// @notice A settlement request with associated signatures
    struct SignedSettlement {
        /// @notice Settlement request
        Settlement settlement;
        /// @notice Signature from the t+ Clearing Engine (CE)
        bytes clearingEngineSignature;
    }

    /// @notice A settlement request with associated signatures
    struct SignedSettlementOrder {
        /// @notice Settlement request
        SettlementOrder settlement;
        /// @notice Signature from the t+ Clearing Engine (CE)
        bytes clearingEngineSignature;
    }

    /**
     * @notice Stores pending settlements for a given (user ID, account_index) pair when batch settlement is used.
     * @dev Target is the address expected to execute the settlement.
     */
    struct PendingSettlement {
        SettlementOrder settlement;
        address target;
    }

    /// @notice Records a withdrawal.
    struct Withdrawal {
        address tokenAddress;
        uint256 amount;
        uint256 nonce;
    }

    /// @notice Information about a settler account.
    struct SettlerInfo {
        address[] executors;
        mapping(address => bool) isExecutor;
    }

    /// @notice Balance of a token for squashing purposes
    struct TokenSquashingBalance {
        /// @notice Address of the token that this balance represents
        address token;
        /// @notice Total quantity of tokens that the vault needs to receive
        uint256 input;
        /// @notice Total quantity of tokens that the vault needs to send
        uint256 output;
        /// @notice Net quantity of tokens that the vault needs to receive
        ///         (i.e., negative implies sending more tokens out than the
        ///         vault is receiving)
        int256 netAmount;
    }

    /// @notice Multisig signer configuration
    struct SignerConfig {
        bytes32 key;
        uint8 keyType;
        uint8 keyPrefix;
        uint32 weight;
        uint64 expiresAtNs;
        uint64 maxSigningWindowNs;
    }

    /// @notice Signals a settlement.
    event Settled(
        bytes32 indexed user,
        uint64 indexed account,
        uint256 indexed nonce,
        address tokenOut,
        uint256 amountOut,
        address tokenIn,
        uint256 amountIn,
        bytes32 settler
    );

    /// @notice Indicates that the set of administrators has been cleared and is now empty
    event AdministratorSetReset();

    /// @notice Signals that the withdrawal quorum has changed
    event WithdrawalQuorumChanged(uint256 previous, uint256 current);

    /// @notice Signals that the credential manager address has changed
    event CredentialManagerChanged(address oldCredentialManager, address newCredentialManager);

    /// @notice Signals that a new administrator has been added to the vault
    event AdminAdded(address newAdmin, uint256 numAdminsAfter);

    /// @notice Signals a deposit
    event Deposited(
        bytes32 indexed user, uint256 indexed nonce, address indexed tokenAddress, uint256 amount
    );

    /// @notice Signals a deposit containing additional multisig signer information
    event DepositedWithConfig(
        bytes32 indexed user,
        uint256 indexed nonce,
        address indexed tokenAddress,
        uint256 amount,
        uint32 masterWeight,
        uint32 lowThreshold,
        uint32 mediumThreshold,
        uint32 highThreshold,
        SignerConfig[] signers,
        bytes masterConfigSignature
    );

    /// @notice Signals a withdrawal.
    event Withdrew(
        bytes32 indexed user, uint256 indexed nonce, address tokenAddress, uint256 amount
    );

    /// @notice Reverts if the caller is not the owner.
    error NotOwner();

    /// @notice Reverts if the specified settler is not an approved settler on
    ///         this vault
    error SettlerNotApproved();

    /// @notice Reverts if the specified depositor is not approved.
    error DepositorNotApproved();

    /// @notice Reverts if the number of callback data payloads does not match
    ///         the number of settlement requests
    error PayloadMismatch();

    /// @notice Reverts if a settlement callback returns an insufficient input token amount
    error InsufficientAmountFromExecutor(uint256 actual, uint256 required);

    /// @notice Reverts if a settlement callback returns insufficient amount for a specific settlement
    error InsufficientCallbackReturnForSettlement(
        uint256 settlementIndex, uint256 actual, uint256 required
    );

    /// @notice Reverts if an insufficient number of blocks have elapsed since the last signature use
    error TooSoon();

    /// @notice Reverts if the caller is not the credential manager
    error NotCredentialManager();

    /// @notice Reverts if a new withdrawal quorum value is equal to zero
    error ZeroWithdrawalQuorum();

    /// @notice Reverts if insufficient administrators are provided when setting the administrators
    error InsufficientAdministrators(uint256 actual, uint256 required);

    /// @notice Reverts if the caller is not an admin.
    error NotAdmin();

    /// @notice Reverts if the caller is not the authorized executor.
    error NotExecutor();

    /// @notice Reverts if a signed operation is past its deadline.
    error Expired();

    /// @notice Reverts if the nonce used in a transaction is incorrect.
    error InvalidNonce(uint256 expected, uint256 given);

    /// @notice Reverts if the signature provided is invalid.
    error InvalidSignature();

    /// @notice Reverts if an order array is empty.
    error EmptyOrders();

    /// @notice Reverts when given the zero address.
    error ZeroAddress();

    /// @notice Reverts when given a zero amount.
    error ZeroAmount();

    /// @notice Reverts when normalizing the deposit amount to 18 decimals would overflow
    error NormalizationOverflow();

    /// @notice Reverts when the token does not implement decimals()
    error DecimalsCallFailed();

    /// @notice Reverts when an insufficient number of signatures are provided for a withdrawal request
    error MissedQuorum(uint256 provided, uint256 required);

    /**
     * @notice Initializes the contract and sets the owner.
     * @param _owner The address to set as the owner.
     * @param _credentialManager The address of the credential manager.
     * @dev Reverts with `ZeroAddress()` if `_owner` is null.
     * @dev Reverts with `ZeroAddress()` if `_credentialManager` is null.
     */
    constructor(address _owner, address _credentialManager) {
        if (_owner == address(0)) revert ZeroAddress();
        if (_credentialManager == address(0)) revert ZeroAddress();
        owner = _owner;
        credentialManager = _credentialManager;
    }

    function isAdministrator(address account) public view returns (bool) {
        for (uint256 i = 0; i < administrators.length; i++) {
            if (administrators[i] == account) return true;
        }

        return false;
    }

    /**
     * @notice Sets the owner of the vault.
     * @dev Reverts with `NotOwner`; Only the owner can set a new owner.
     */
    function setOwner(address newOwner) external {
        if (msg.sender != owner) revert NotOwner();
        if (newOwner == address(0)) revert ZeroAddress();
        owner = newOwner;
    }

    function setCredentialManager(address newCredentialManager) external {
        if (msg.sender != owner) revert NotOwner();
        if (newCredentialManager == address(0)) revert ZeroAddress();
        /* TODO(jmcph4): check against `latestApproval`! */
        if (block.number >= lastSignatureUse + credentialManagerChangeDelayBlocks) {
            revert TooSoon();
        }
        address oldCredentialManager = credentialManager;
        credentialManager = newCredentialManager;
        emit CredentialManagerChanged(oldCredentialManager, newCredentialManager);
    }

    function setAdministrators(address[] calldata newAdministrators, uint256 newWithdrawalQuorum)
        external
    {
        if (msg.sender != credentialManager) revert NotCredentialManager();
        if (newWithdrawalQuorum < 1) revert ZeroWithdrawalQuorum();
        if (newAdministrators.length < newWithdrawalQuorum) {
            revert InsufficientAdministrators(newAdministrators.length, newWithdrawalQuorum);
        }

        // It's critical there are no zero-addresses; otherwise, errored signatures may mistakenly pass.
        for (uint256 i = 0; i < newAdministrators.length; i++) {
            if (newAdministrators[i] == address(0)) revert ZeroAddress();
        }

        administrators = newAdministrators;
        emit AdministratorSetReset();

        for (uint256 i = 0; i < administrators.length; i++) {
            address currAdmin = administrators[i];
            emit AdminAdded(currAdmin, i + 1);
        }

        uint256 oldWithdrawalQuorum = withdrawalQuorum;
        withdrawalQuorum = newWithdrawalQuorum;
        if (oldWithdrawalQuorum != newWithdrawalQuorum) {
            emit WithdrawalQuorumChanged(oldWithdrawalQuorum, newWithdrawalQuorum);
        }
    }

    /**
     * @notice Sets the domain separators for EIP-712 signatures.
     * @param domainSeparator: The value to set.
     * @dev Reverts with `NotOwner`; Only the admin can set the domain separator.
     */
    function setDomainSeparator(bytes32 domainSeparator) external {
        if (msg.sender != owner) revert NotOwner();
        require(_domainSeparator == 0); // dev: Already set.
        _domainSeparator = domainSeparator;
    }

    /**
     * @notice Sets the settle executor.
     * @param settler: The settler's tplus account key.
     * @param executor: The settler's assigned executor address.
     * @dev Reverts with `NotOwner`; Only the admin can set the settler executor.
     */
    function addSettlerExecutor(bytes32 settler, address executor) external {
        if (msg.sender != owner) revert NotOwner();

        if (!settlerIsApproved[settler]) {
            approvedSettlers.push(settler);
            settlerIsApproved[settler] = true;
        }

        SettlerInfo storage data = settlerExecutorMap[settler];
        if (!data.isExecutor[executor]) {
            data.executors.push(executor);
            data.isExecutor[executor] = true;
        }
    }

    /**
     * @notice Removes a settler.
     * @param settler: The settler's tplus account key.
     * @dev Reverts with `NotOwner`; Only the admin can remove a settler.
     */
    function removeSettler(bytes32 settler) external {
        if (msg.sender != owner) revert NotOwner();
        uint256 length = approvedSettlers.length;

        settlerIsApproved[settler] = false;

        for (uint256 i = 0; i < length; i++) {
            if (approvedSettlers[i] == settler) {
                // Move last element to this spot and pop the last element.
                approvedSettlers[i] = approvedSettlers[length - 1];
                approvedSettlers.pop();
                break;
            }
        }

        // Remove all executors.
        SettlerInfo storage info = settlerExecutorMap[settler];
        for (uint256 i = 0; i < info.executors.length; i++) {
            address exec = info.executors[i];
            info.isExecutor[exec] = false;
        }
        delete info.executors;
    }

    /**
     * @notice Deposits a token into the vault.
     * @param user: The user whose account will be credited with the deposit.
     * @param tokenAddress: The address of the token to deposit.
     * @param amount: The amount of the token to deposit.
     * @dev Reverts if the amount is 0.
     */
    function deposit(bytes32 user, address tokenAddress, uint256 amount) external {
        uint256 nonce = _deposit(user, tokenAddress, amount);
        emit Deposited(user, nonce, tokenAddress, amount);
    }

    /**
     * @notice Deposits a token into the vault with additional multisig signer configuration.
     * @param user: The user whose account will be credited with the deposit.
     * @param tokenAddress: The address of the token to deposit.
     * @param amount: The amount of the token to deposit.
     * @dev Reverts if the amount is 0.
     */
    function deposit(
        bytes32 user,
        address tokenAddress,
        uint256 amount,
        uint32 masterWeight,
        uint32 lowThreshold,
        uint32 mediumThreshold,
        uint32 highThreshold,
        SignerConfig[] calldata signers,
        bytes calldata masterConfigSignature
    ) external {
        uint256 nonce = _deposit(user, tokenAddress, amount);
        emit DepositedWithConfig(
            user,
            nonce,
            tokenAddress,
            amount,
            masterWeight,
            lowThreshold,
            mediumThreshold,
            highThreshold,
            signers,
            masterConfigSignature
        );
    }

    function _deposit(bytes32 user, address tokenAddress, uint256 amount)
        internal
        returns (uint64 nonce)
    {
        if (!canDeposit[msg.sender]) revert DepositorNotApproved();
        if (amount == 0) revert ZeroAmount();

        // Ensure the deposit amount won't overflow when the clearing engine
        // normalizes it to CLEARING_ENGINE_DECIMALS.
        uint8 decimals = _getDecimals(tokenAddress);
        if (decimals < CLEARING_ENGINE_DECIMALS) {
            uint256 scalingFactor = 10 ** (CLEARING_ENGINE_DECIMALS - decimals);
            if (amount > type(uint256).max / scalingFactor) revert NormalizationOverflow();
        }

        nonce = depositCounts[user];
        depositCounts[user] = nonce + 1;

        SafeTransferLib.safeTransferFrom(tokenAddress, msg.sender, address(this), amount);
        return nonce;
    }

    function _getDecimals(address tokenAddress) internal view returns (uint8) {
        (bool success, bytes memory data) =
            tokenAddress.staticcall(abi.encodeWithSignature("decimals()"));
        if (!success || data.length < 32) revert DecimalsCallFailed();
        return abi.decode(data, (uint8));
    }

    // TODO: Delete this method and notion of approved-depositor before official production.
    function setDepositorStatus(address depositor, bool allowed) external {
        if (msg.sender != owner) revert NotOwner();
        canDeposit[depositor] = allowed;
    }

    /**
     * @notice Executes an atomic settlement.
     * @param order: The settlement order.
     * @param settler: The t+ identity of the settler executing this order.
     * @param data: The data to execute as part of settlement callback.
     * @param signature: The signature from the t+ clearing engine.
     * @dev Reverts with `Expired` if the block timestamp is greater than `validUntil`.
     * @dev Reverts with `SettlerNotApproved` if the settler is not in the approved set.
     * @dev Reverts with `NotExecutor`; Only the executor can settle.
     * @dev Reverts with `InvalidNonce` if the nonce has already been used.
     * @dev Reverts with `InvalidSignature` if the signer is not an admin.
     * @dev Reverts with `InsufficientAmountFromExecutor` if the `order.amountIn` is less than what the executor reports
     */
    function executeAtomicSettlement(
        Settlement calldata order,
        bytes32 settler,
        bytes calldata data,
        bytes calldata signature
    ) external {
        bytes32 user = order.user;
        uint64 account = order.account;
        uint256 validUntil = order.validUntil;

        if (block.timestamp > validUntil) revert Expired();
        if (!settlerIsApproved[settler]) revert SettlerNotApproved();
        if (!settlerExecutorMap[settler].isExecutor[msg.sender]) revert NotExecutor();

        uint256 expectedNonce = settlementCounts[user][account];
        if (order.nonce != expectedNonce) revert InvalidNonce(expectedNonce, order.nonce);

        bytes32 digest = keccak256(
            bytes.concat(
                SETTLEMENT_TYPEHASH,
                _domainSeparator,
                bytes32(uint256(uint160(order.tokenOut)) << 96),
                bytes32(order.amountOut),
                bytes32(uint256(uint160(order.tokenIn)) << 96),
                bytes32(order.amountIn),
                user,
                bytes32(uint256(uint160(account))),
                bytes32(order.nonce),
                bytes32(validUntil),
                settler
            )
        );

        // Check the signature and record latest signature usage if it's valid
        checkApproval(digest, signature);
        lastSignatureUse = block.number;

        // Ensure to bump the nonce _before_ the callback to avoid signature replay.
        settlementCounts[user][account] += 1;

        // Invoke callback on the executor
        uint256 expectedAmountIn = IAtomicSettlementCallback(msg.sender)
            .onAtomicSettlement(order.tokenOut, order.amountOut, data);
        if (expectedAmountIn < order.amountIn) {
            revert InsufficientAmountFromExecutor(expectedAmountIn, order.amountIn);
        }

        // Transfer tokens IN from the executor
        SafeTransferLib.safeTransferFrom(order.tokenIn, msg.sender, address(this), expectedAmountIn);

        // Transfer tokens OUT to the executor
        SafeTransferLib.safeTransfer(order.tokenOut, msg.sender, order.amountOut);

        emit Settled(
            user,
            account,
            order.nonce,
            order.tokenOut,
            order.amountOut,
            order.tokenIn,
            order.amountIn,
            settler
        );
    }

    /// @notice Execute a sequence of settlement requests in a squashing fashion
    /// @param requests List of settlement requests
    function executeSquashingSettlements(
        SignedSettlement[] calldata requests,
        bytes[] calldata data,
        bytes32 settler
    ) external {
        address caller = msg.sender;
        uint256 numRequests = requests.length;
        uint256 numDataPayloads = data.length;
        if (numRequests != numDataPayloads) revert PayloadMismatch();

        /**
         * SAFETY(jmcph4): Check that settler is approved
         *
         * This prevents unauthorised settlers from executing settlements.
         */
        if (!settlerIsApproved[settler]) revert SettlerNotApproved();

        /**
         * SAFETY(jmcph4): Check that the caller is an assigned executor for this settler
         *
         * This prevents unauthorised execution of valid settlement requests.
         */
        if (!settlerExecutorMap[settler].isExecutor[caller]) revert NotExecutor();

        // Allocate token balances for netting off
        TokenSquashingBalance[] memory balances = new TokenSquashingBalance[](numRequests * 2);
        uint256 numUniqueTokens = 0;

        for (uint256 i = 0; i < numRequests; i++) {
            SignedSettlement memory currRequest = requests[i];
            bytes32 user = currRequest.settlement.user;
            uint64 account = currRequest.settlement.account;
            uint256 actualNonce = currRequest.settlement.nonce;
            uint256 validUntil = currRequest.settlement.validUntil;
            address tokenIn = currRequest.settlement.tokenIn;
            address tokenOut = currRequest.settlement.tokenOut;
            uint256 amountIn = currRequest.settlement.amountIn; /* TODO(jmcph4): callback */
            uint256 amountOut = currRequest.settlement.amountOut;

            /**
             * SAFETY(jmcph4): Check expiry
             *
             * This prevents stale settlement requests from being executed.
             */
            if (block.timestamp > validUntil) revert Expired();

            /**
             * SAFETY(jmcph4): Check nonce
             *
             * This prevents replay attacks on settlement requests.
             */
            uint256 expectedNonce = settlementCounts[user][account];
            if (actualNonce < expectedNonce) revert InvalidNonce(expectedNonce, actualNonce);

            bytes32 digest = keccak256(
                bytes.concat(
                    SETTLEMENT_TYPEHASH,
                    _domainSeparator,
                    bytes32(uint256(uint160(tokenOut)) << 96),
                    bytes32(amountOut),
                    bytes32(uint256(uint160(tokenIn)) << 96),
                    bytes32(amountIn),
                    user,
                    bytes32(uint256(uint160(account))),
                    bytes32(actualNonce),
                    bytes32(validUntil)
                )
            );

            /**
             * SAFETY(jmcph4): Verify t+ Clearing Engine (CE) signature
             *
             * This prevents unauthorised settlements.
             */
            checkApproval(digest, requests[i].clearingEngineSignature); /* TODO(jmcph4): horrific calldata load */
            lastSignatureUse = block.number;

            /**
             * SAFETY(jmcph4): Increment settlement nonce prior to invoking the
             *                  callback
             *
             * This prevents replay attacks (reentrant or otherwise) on
             * settlement requests.
             */
            settlementCounts[user][account] += 1;

            // Apply this request to running net token balances
            bool inputFound = false;
            bool outputFound = false;
            for (uint256 j = 0; j < numUniqueTokens; j++) {
                if (balances[j].token == tokenIn) {
                    balances[j].input += amountIn;
                    inputFound = true;
                    break;
                }
            }

            if (!inputFound) {
                balances[numUniqueTokens] = TokenSquashingBalance(tokenIn, amountIn, 0, 0);
                numUniqueTokens++;
            }

            for (uint256 j = 0; j < numUniqueTokens; j++) {
                if (balances[j].token == tokenOut) {
                    balances[j].output += amountOut;
                    outputFound = true;
                    break;
                }
            }

            if (!outputFound) {
                balances[numUniqueTokens] = TokenSquashingBalance(tokenOut, 0, amountOut, 0);
                numUniqueTokens++;
            }
        }

        // Net off each token balance
        for (uint256 i = 0; i < numUniqueTokens; i++) {
            if (balances[i].input > balances[i].output) {
                balances[i].netAmount = int256(balances[i].input - balances[i].output);
            } else if (balances[i].output > balances[i].input) {
                balances[i].netAmount = -int256(balances[i].output - balances[i].input);
            }
        }

        // Push funds out from the vault and into the executor
        for (uint256 i = 0; i < numUniqueTokens; i++) {
            // Negative net amount implies that we must push funds out from the vault
            if (balances[i].netAmount < 0) {
                // Transfer tokens OUT to the executor
                SafeTransferLib.safeTransfer(
                    balances[i].token, caller, uint256(-balances[i].netAmount)
                );
            }
        }

        // Call callbacks and record return values
        uint256[] memory callbackReturns = new uint256[](numRequests);

        for (uint256 i = 0; i < numRequests; i++) {
            Settlement memory request = requests[i].settlement;

            /**
             * SAFETY(jmcph4): Record callback return value
             *
             * The executor reports how much of tokenIn it will provide for this
             * specific settlement. Pass the per-settlement amountOut, not the net.
             * These values will be validated against requirements before pulling funds.
             */
            callbackReturns[i] = IAtomicSettlementCallback(msg.sender)
                .onAtomicSettlement(request.tokenOut, request.amountOut, data[i]);

            /**
             * SAFETY(jmcph4): Validate per-settlement callback return
             *
             * Ensure the executor commits to provide at least the promised amountIn
             * for THIS specific settlement. This prevents cross-settlement subsidization
             * where an executor could shortchange one user while overpaying another.
             */
            if (callbackReturns[i] < request.amountIn) {
                revert InsufficientCallbackReturnForSettlement(
                    i, callbackReturns[i], request.amountIn
                );
            }
        }

        // Validate callback returns and pull funds
        for (uint256 i = 0; i < numUniqueTokens; i++) {
            // Only process tokens that need to be pulled (positive net amount)
            if (balances[i].netAmount > 0) {
                address token = balances[i].token;
                uint256 requiredAmount = uint256(balances[i].netAmount);

                /**
                 * SAFETY(jmcph4): Sum callback returns by token
                 *
                 * Calculate total amount the executor has committed to provide
                 * for this token across all settlements.
                 */
                uint256 totalCallbackAmount = 0;
                for (uint256 j = 0; j < numRequests; j++) {
                    if (requests[j].settlement.tokenIn == token) {
                        totalCallbackAmount += callbackReturns[j];
                    }
                }

                /**
                 * SAFETY(jmcph4): Validate executor commitment
                 *
                 * Ensure the executor has committed to provide at least the
                 * required net amount for this token.
                 */
                if (totalCallbackAmount < requiredAmount) {
                    revert InsufficientAmountFromExecutor(totalCallbackAmount, requiredAmount);
                }

                // Transfer tokens IN from the executor
                SafeTransferLib.safeTransferFrom(token, caller, address(this), requiredAmount);
            }
        }

        // Emit settlement events
        for (uint256 i = 0; i < numRequests; i++) {
            Settlement memory request = requests[i].settlement;

            /**
             * SAFETY(jmcph4): Emit per-settlement amounts
             *
             * Events must reflect the actual per-settlement amounts, not the netted
             * amounts. This ensures proper accounting and allows off-chain systems
             * to correctly track what each user received.
             */
            emit Settled(
                request.user,
                request.account,
                request.nonce,
                request.tokenOut,
                request.amountOut,
                request.tokenIn,
                request.amountIn,
                settler
            );
        }
    }

    /**
     * @notice Pulls funds for execution during a settlement batch.
     * @param orders: The settlement orders.
     * @param user: The t+ user who is executing the settlement.
     * @param target: The target address to send the token to, pull tokens from, and execute callback on.
     * @param validUntil: The timestamp when the settlement signature expires.
     * @dev Reverts with `Expired` if the block timestamp is greater than `validUntil`.
     * @dev Reverts if a batch settlement has already started.
     * @dev Reverts with `NotAdmin`; Only an admin can execute the settlement.
     * @dev Reverts with `InvalidNonce` if the nonce has already been used.
     * @dev Reverts with `SignatureError` if the signer is not an admin.
     */
    function pullBatchSettlements(
        SignedSettlementOrder[] calldata orders,
        bytes32 user,
        uint64 account,
        address target,
        uint256 validUntil
    ) external {
        if (block.timestamp > validUntil) revert Expired();
        require(pendingSettlements[user][account].length == 0);
        if (!isAdministrator(msg.sender)) revert NotAdmin();

        uint256 expectedNonce = settlementCounts[user][account];
        bytes32 domainSeparator = _domainSeparator;
        uint64 ordersLength = uint64(orders.length);
        if (ordersLength == 0) revert EmptyOrders();

        for (uint256 i = 0; i < ordersLength; ++i) {
            SettlementOrder calldata s = orders[i].settlement;

            uint256 nonce = s.nonce;
            if (nonce != expectedNonce) revert InvalidNonce(expectedNonce, nonce);

            bytes32 digest = keccak256(
                bytes.concat(
                    SETTLEMENT_TYPEHASH,
                    domainSeparator,
                    bytes32(uint256(uint160(s.tokenOut)) << 96),
                    bytes32(s.amountOut),
                    bytes32(uint256(uint160(s.tokenIn)) << 96),
                    bytes32(s.amountIn),
                    user,
                    bytes32(uint256(uint160(account))),
                    bytes32(s.nonce),
                    bytes32(validUntil)
                )
            );

            checkApproval(digest, orders[i].clearingEngineSignature);
            expectedNonce = nonce + 1;

            pendingSettlements[user][account].push(
                PendingSettlement({settlement: s, target: target})
            );
            SafeTransferLib.safeTransfer(s.tokenOut, target, s.amountOut);
        }

        settlementCounts[user][account] += ordersLength;
    }

    /**
     * @notice Pushes expected funds from a batch settlement to the deposit vault.
     * @param user: The t+ user who is executing the settlement.
     * @param account: The account of the t+ user to execute settlement against
     * @dev Reverts with `NotAdmin`; Only an admin can execute the settlement.
     */
    function pushBatchSettlements(bytes32 user, uint64 account) external {
        if (!isAdministrator(msg.sender)) revert NotAdmin();

        for (uint32 i = 0; i < pendingSettlements[user][account].length; i++) {
            PendingSettlement memory pendingSettlement = pendingSettlements[user][account][i];

            SafeTransferLib.safeTransferFrom(
                pendingSettlement.settlement.tokenIn,
                pendingSettlement.target,
                address(this),
                pendingSettlement.settlement.amountIn
            );
            emit Settled(
                user,
                account,
                pendingSettlement.settlement.nonce,
                pendingSettlement.settlement.tokenOut,
                pendingSettlement.settlement.amountOut,
                pendingSettlement.settlement.tokenIn,
                pendingSettlement.settlement.amountIn,
                bytes32(0)
            );
        }
        delete pendingSettlements[user][account];
    }

    /**
     * @notice Withdraws a token from the vault.
     * @param withdrawal: The withdrawal token and amount.
     * @param user: The user whose account will be debited by the withdrawal.
     * @param target: The target address to send the token to.
     * @param validUntil: The timestamp when the withdrawal signature expires.
     * @param signatures: t+ clearing engine signatures.
     * @dev Reverts with `Expired` if the block timestamp is greater than `validUntil`.
     * @dev Reverts with `InvalidNonce` if the nonce has already been used.
     * @dev Reverts with `SignatureError` if the signer is not an admin.
     */
    function withdraw(
        Withdrawal calldata withdrawal,
        bytes32 user,
        address target,
        uint256 validUntil,
        bytes32 epochHash,
        bytes[] calldata signatures
    ) external {
        /* PERF(jmcph4): cache storage variable to the stack */
        uint256 quorum = withdrawalQuorum;
        if (block.timestamp > validUntil) revert Expired();
        if (signatures.length < withdrawalQuorum) {
            revert MissedQuorum(signatures.length, quorum);
        }

        uint256 expectedNonce = withdrawalCounts[user];
        if (withdrawal.nonce != expectedNonce) {
            revert InvalidNonce(expectedNonce, withdrawal.nonce);
        }

        /**
         * BEGIN SIGNATURE CHECKS *************************
         */

        // Set of administrators that have provided signatures for this withdrawal
        address[] memory seenAdmins = new address[](signatures.length);
        uint256 numSeenAdmins = 0;

        // PERF(jmcph4): No need to recompute inside the loop body
        bytes32 digest = keccak256(
            bytes.concat(
                WITHDRAWAL_TYPEHASH,
                _domainSeparator,
                bytes32(uint256(uint160((withdrawal.tokenAddress))) << 96),
                bytes32(withdrawal.amount),
                user,
                bytes32(withdrawal.nonce),
                bytes32(validUntil),
                bytes32(epochHash),
                bytes32(uint256(uint160(target)) << 96)
            )
        );

        for (uint256 i = 0; i < signatures.length; i++) {
            /* Verify the signature.
             *
             * This determines whether the digest is really signed by the provided
             * signature and computes the signer's address.
             */
            address signer = ECDSA.tryRecoverCalldata(digest, signatures[i]);
            if (signer == address(0)) revert InvalidSignature();

            // Check that the recovered signer is in fact an administrator
            if (!isAdministrator(signer)) revert InvalidSignature();

            /* Check that this administrator is unique. Without this step, a
             * single admin could provide `k` signatures where `k == withdrawalQuorum`
             * and we'd happily approve the withdrawal.
             */
            bool isCurrentSignerUnique = true;
            for (uint256 j = 0; j < numSeenAdmins; j++) {
                if (seenAdmins[j] == signer) {
                    isCurrentSignerUnique = false;
                    break;
                }
            }
            if (isCurrentSignerUnique) {
                seenAdmins[numSeenAdmins] = signer;
                numSeenAdmins++;
            }
            if (numSeenAdmins == quorum) break;
        }

        if (numSeenAdmins < quorum) revert MissedQuorum(numSeenAdmins, quorum);

        /**
         * END SIGNATURE CHECKS *************************
         */

        // SAFETY(jmcph4): Purposely bump the nonce as close to signature verification as possible, to alleviate callback concerns.
        withdrawalCounts[user] += 1;

        // Record latest signature usage
        lastSignatureUse = block.number;

        SafeTransferLib.safeTransfer(withdrawal.tokenAddress, target, withdrawal.amount);
        emit Withdrew(user, withdrawal.nonce, withdrawal.tokenAddress, withdrawal.amount);
    }

    /**
     * @notice Get the array of approved settlers.
     * @return An array of addresses (as bytes32) that are currently approved settlers.
     */
    function getApprovedSettlers() external view returns (bytes32[] memory) {
        return approvedSettlers;
    }

    // TODO: Delete this method before official production.
    function ownerWithdrawToken(address token, address to, uint256 amount) external {
        if (msg.sender != owner) revert NotOwner();
        require(to != address(0));
        SafeTransferLib.safeTransfer(token, to, amount);
    }

    function checkApproval(bytes32 digest, bytes calldata signature) internal view {
        address signer = ECDSA.tryRecoverCalldata(digest, signature);
        if (signer == address(0)) revert InvalidSignature();
        if (!isAdministrator(signer)) revert InvalidSignature();
    }
}

