// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

/**
 * @title Registry
 * @notice Central registry for managing assets and associated risk parameters across multiple chains.
 * @dev Uses admin and multisig roles to control sensitive operations like asset registration and risk configuration.
 */
contract Registry {
    /// @notice Address of the admin; primarily used for initial setup.
    address public admin;

    /// @notice Multisig wallet address responsible for managing risk-related configurations.
    address public riskManagerMultisig;

    /// @notice Number of seconds to wait before new risk parameters become effective
    uint256 public riskParameterChangeDelaySeconds = 1 days;

    /// @notice Mapping of asset index to new risk parameters to be applied to the registry, but only after they become eligible
    mapping(uint16 => PendingRiskParameters) public pendingRiskParameters;

    /// @notice Mapping of asset index to associated risk parameters.
    mapping(uint16 => RiskParameters) public riskParameters;

    /// @notice Registry of all registered assets and associated chain data.
    AssetRegistry assets;

    /// @notice Reverse mapping: routingId => vmId => assetAddress => asset index + 1 (0 means not found).
    mapping(uint64 => mapping(uint64 => mapping(bytes32 => uint256))) assetIndexLookup;

    /// @notice Account for receiving fees and paying rewards.
    bytes32 public feeAccount;

    /// @notice Withdrawal delay parameters, used to calculate delays between request and execution of withdrawals.
    WithdrawalDelayParameters withdrawalDelayParameters;

    /// @notice Pending withdrawal delay parameters to be applied after the delay period.
    PendingWithdrawalDelayParameters public pendingWithdrawalDelayParameters;

    /// @notice Signals that the maximum deposit has changed for a given asset
    event MaxDepositChanged(ChainId chain, uint16 index, uint256 previous, uint256 current);

    /// @notice Signals that the maximum hourly deposit has changed for a given asset
    event Max1HrDepositChanged(ChainId chain, uint16 index, uint256 previous, uint256 current);

    /// @notice Signals that the minimum weight has changed for a given asset
    event MinWeightChanged(ChainId chain, uint16 index, uint256 previous, uint256 current);

    /// @notice Defines risk-related configuration parameters for an asset.
    struct RiskParameters {
        /// @notice Percentage of asset value that can be counted as collateral (e.g., 90 = 90%).
        uint8 collateralFactor;

        /// @notice Percentage multiplier applied to liabilities for risk calculations (e.g., 90 = 90%).
        uint8 liabilityFactor;

        /// @notice Maximum allowable collateral amount for this asset. May be unenforced on-chain.
        uint256 maxCollateral;

        /// @notice Maximum total open interest allowed for derivatives positions.
        uint256 maxOpenInterest;

        /// @notice Maximum open interest allowed for spot positions.
        uint256 maxSpotOpenInterest;

        /// @notice Maximum allowed utilization ratio of available liquidity.
        uint256 maxUtilization;

        /// @notice If true, asset can only be used in isolated margin mode.
        bool isolatedOnly;

        /// @notice Utilization points where the interest rate curve slope changes, scaled in 1/100th of a basis point.
        uint256[] interestKinks;

        /// @notice Interest rates corresponding to `interestKinks`, scaled in 1/100th of a basis point.
        uint256[] kinkInterestRates;

        /// @notice USD-denominated utilization kink points, scaled in 1/100th of a basis point.
        uint256[] usdInterestKinks;

        /// @notice USD-denominated interest rates corresponding to `usdInterestKinks`, scaled in 1/100th of a basis point.
        uint256[] usdKinkInterestRates;

        /// @notice Multiplier applied to skew-based pricing adjustments, scaled in 1/100th of a basis point.
        uint256 skewModifier;

        /// @notice Skew threshold at which maximum skew adjustment applies, scaled in 1/100th of a basis point.
        uint256 skewCliff;

        /// @notice Base funding rate applied regardless of skew direction, scaled in 1/100th of a basis point.
        int256 baseFundingRate;

        /// @notice Maximum allowed premium adjustment, scaled in 1/100th of a basis point.
        uint256 premiumClamp;

        /// @notice Maximum premium impact applied during initial margin calculation, scaled in 1/100th of a basis point.
        uint256[] initialMarginClamps;

        /// @notice Multipliers applied to position size when calculating initial margin, scaled in 1/100th of a basis point.
        uint256[] initialMarginFactors;

        /// @notice Maximum absolute funding rate allowed, scaled in 1/100th of a basis point.
        uint256 maxFundingRate;

        /// @notice Maximum interest rate applied at full utilization, scaled in 1/100th of a basis point.
        uint256 maxUtilizationRate;

        /// @notice Additional safety buffer multiplier applied to risk calculations, scaled in 1/100th of a basis point.
        uint256 bufferMultiple;
    }

    struct PendingRiskParameters {
        RiskParameters parameters;
        uint256 validAfter;
    }

    /**
     * @notice Struct for managing a list of registered assets.
     * @dev Assets are stored by index and can span multiple chains.
     */
    struct AssetRegistry {
        uint256 count; // Total number of assets.
        uint256 totalEntries; // Total number of (chain, address) entries across all assets.
        mapping(uint16 => Asset) registry; // Mapping from index to asset struct.
    }

    struct WithdrawalDelayParameters {
        /// @notice Minimum delay for zero cumulative, in seconds.
        uint256 minDelay;

        /// @notice Maximum delay cap, in seconds.
        uint256 maxDelay;

        /// @notice Cumulative capacity thresholds, scaled in 1/100th of a basis point.
        uint256[] delayClamps;

        /// @notice Delay duration at each clamp, in seconds.
        uint256[] delayValues;

        /// @notice Floor for the potential function denominator.
        uint256 capFloor;
    }

    struct PendingWithdrawalDelayParameters {
        WithdrawalDelayParameters parameters;
        uint256 validAfter;
    }

    /**
     * @notice Struct for identifying a chain.
     */
    struct ChainId {
        // The routing ID e.g. 0=EVM style chains.
        uint64 routingId;

        // e.g. EVM chainId.
        uint64 vmId;
    }

    /**
     * @notice Struct representing an asset across multiple chains and addresses.
     */
    struct Asset {
        // Routing ID => Chain ID => Address => AssetData.
        mapping(uint64 => mapping(uint64 => mapping(bytes32 => AssetData))) data;

        // List of all known chain IDs for this asset.
        ChainId[] chains;

        // Parallel array of asset addresses, one per chain entry.
        bytes32[] addresses;
    }

    /**
     * @notice Chain-specific metadata for an asset.
     * @dev Uses bytes32 for `assetAddress` to support non-EVM chains like Solana.
     */
    struct AssetData {
        uint16 index;
        bytes32 assetAddress;
        ChainId chainId;
        uint256 maxDeposits; // Cap on deposits (collateral cap).
        uint256 max1hrDeposits; // Cap on fungible deposits over one hour
        uint256 minWeight; // Raw weight value (not percentage)
    }

    /// @notice Reverts if caller is not the admin.
    error NotAdmin();

    /// @notice Reverts if there is are no risk parameters queued for the specified asset
    error NoPendingRiskParameters(uint16 asset);

    /// @notice Reverts if the pending risk parameters are not yet eligible for application
    error TooSoon(uint16 asset, uint256 eligibleAt);

    /// @notice Reverts if caller is not the risk manager multisig.
    error NotRiskManager();

    /// @notice Reverts if the asset index is out of bounds.
    error IndexOutOfBounds();

    /// @notice Reverts if the collateral factor (CF) specified as part of risk parameters is greater than one
    error InvalidCollateralFactor();

    /// @notice Reverts if the liability factor (LF) specified as part of risk parameters is greater than one
    error InvalidLiabilityFactor();

    /// @notice Reverts if the utilization cap specified as part of risk parameters is greater than one
    error InvalidUtilizationCap();

    /// @notice Reverts if the funding rate cap specified as part of risk parameters is greater than ~1000% APR
    error InvalidMaxFundingRate();

    /// @notice Reverts if the utilization rate cap specified as part of risk parameters is greater than ~1000% APR
    error InvalidMaxUtilizationRate();

    /// @notice Reverts if the buffer multiple value is less than 1% or greater than 2%.
    error InvalidBufferMultiple();

    /// @notice Reverts if the interest kinks specified as part of risk parameters are not increasing from 0 to 1
    error InvalidInterestKinks();

    /// @notice Reverts if the interest rates specified as part of risk parameters are not increasing
    error InvalidRateInterestKinks();

    /// @notice Reverts if the USD-denominated interest kinks specified as part of risk parameters are not increasing from 0 to 1
    error InvalidUSDInterestKinks();

    /// @notice Reverts if the USD-denominated interest rates specified as part of risk parameters are not increasing
    error InvalidUSDRateInterestKinks();

    /// @notice Reverts if the size of the initial margin clamps does not match the size of the initial margin factors (specified as part of risk parameters)
    error InvalidInitialMarginsConfiguration();

    /// @notice Reverts if the initial margin clamps specified as part of risk parameters are not increasing or are above 100
    error InvalidInitialMarginsClamps();

    /// @notice Reverts if the initial margin clamps specified as part of risk parameters are not decreasing or are above 100
    error InvalidInitialMarginsFactors();

    /// @notice Reverts if the withdrawal delay clamps and values arrays have different lengths.
    error InvalidWithdrawalDelayConfiguration();

    /// @notice Reverts if the withdrawal delay clamps are not monotonically increasing from zero.
    error InvalidWithdrawalDelayClamps();

    /// @notice Reverts if the withdrawal delay values are not monotonically increasing.
    error InvalidWithdrawalDelayValues();

    /// @notice Reverts if minDelay > maxDelay.
    error InvalidWithdrawalDelayBounds();

    /// @notice Reverts if a withdrawal delay value is outside [minDelay, maxDelay].
    error WithdrawalDelayValueOutOfBounds();

    /// @notice Reverts if there are no pending withdrawal delay parameters.
    error NoPendingWithdrawalDelayParameters();

    /// @notice Reverts if the pending withdrawal delay parameters are not yet eligible.
    error WithdrawalDelayParametersTooSoon(uint256 eligibleAt);

    /// @notice Reverts if an address is zero.
    error ZeroAddress();

    /// @notice Reverts if the risk manager is not set.
    error RiskManagerNotSet();

    /**
     * @notice Contract constructor.
     * @param _admin The admin controller of the vault.
     * @dev Sets the deployer as the initial admin.
     */
    constructor(address _admin) {
        admin = _admin;
    }

    /**
     * @notice Updates the risk manager multisig address.
     * @param multisig The new address to set.
     * @dev Reverts with `NotAdmin`; Only the admin can set a risk manager.
     */
    function setRiskManagerMultisig(address multisig) external {
        if (msg.sender != admin) revert NotAdmin();
        riskManagerMultisig = multisig;
    }

    /**
     * @notice Updates the admin address.
     * @param newAdmin The new admin address.
     * @dev Reverts with `NotAdmin`; Only the admin can set a new admin.
     * @dev The new administrator address is allowed to be the null address.
     *      Setting the administrator to this address disables administration
     *      of the registry contract.
     */
    function setAdmin(address newAdmin) external {
        if (msg.sender != admin) revert NotAdmin();
        if (newAdmin == address(0) && riskManagerMultisig == address(0)) {
            revert RiskManagerNotSet();
        }
        admin = newAdmin;
    }

    /**
     * @notice Sets or updates asset data for a specific asset index and chain.
     * @dev Automatically adds new assets or chain instances if not already present.
     * @param data The chain-specific asset data.
     * @dev Reverts with `NotRiskManager`; Only the risk manager can set asset data.
     */
    function setAssetData(AssetData memory data) external {
        if (msg.sender != riskManagerMultisig) revert NotRiskManager();
        if (data.index > assets.count) revert IndexOutOfBounds();

        // Prevent registering asset with zero-address. Zero-address means that asset
        // has not yet been set on a chain, where is this case it has.
        if (data.assetAddress == bytes32(0)) revert ZeroAddress();

        Asset storage reg = assets.registry[data.index];

        uint64 routingId = data.chainId.routingId;
        uint64 vmId = data.chainId.vmId;

        bool isNewEntry = reg.data[routingId][vmId][data.assetAddress].assetAddress == bytes32(0);
        reg.data[routingId][vmId][data.assetAddress] = data;

        if (isNewEntry) {
            if (data.index == assets.count) {
                assets.count += 1;
            }
            reg.chains.push(data.chainId);
            reg.addresses.push(data.assetAddress);
            assets.totalEntries += 1;
            // Store index + 1 so that 0 means "not found".
            assetIndexLookup[routingId][vmId][data.assetAddress] = uint256(data.index) + 1;
        }
    }

    /**
     * @notice Removes an asset address entry for a specific asset index and chain.
     * @param chainId The chain to remove the address from.
     * @param index The asset index.
     * @param assetAddress The address to remove.
     * @dev Reverts with `NotRiskManager`; Only the risk manager can remove asset data.
     */
    function removeAssetData(ChainId calldata chainId, uint16 index, bytes32 assetAddress)
        external
    {
        if (msg.sender != riskManagerMultisig) revert NotRiskManager();
        require(index < assets.count, "!asset");

        Asset storage reg = assets.registry[index];
        uint64 routingId = chainId.routingId;
        uint64 vmId = chainId.vmId;

        if (reg.data[routingId][vmId][assetAddress].assetAddress == bytes32(0)) {
            revert ZeroAddress();
        }

        delete reg.data[routingId][vmId][assetAddress];
        delete assetIndexLookup[routingId][vmId][assetAddress];

        // Remove from parallel arrays by swapping with the last element.
        uint256 len = reg.chains.length;
        for (uint256 i = 0; i < len; i++) {
            if (
                reg.chains[i].routingId == routingId && reg.chains[i].vmId == vmId
                    && reg.addresses[i] == assetAddress
            ) {
                reg.chains[i] = reg.chains[len - 1];
                reg.addresses[i] = reg.addresses[len - 1];
                reg.chains.pop();
                reg.addresses.pop();
                assets.totalEntries -= 1;
                break;
            }
        }
    }

    function setMaxDeposits(
        ChainId calldata chainId,
        uint16 index,
        bytes32 assetAddress,
        uint256 newMaxDeposit
    ) external {
        if (msg.sender != riskManagerMultisig) revert NotRiskManager();
        require(index < assets.count, "!asset");

        uint64 routingId = chainId.routingId;
        uint64 vmId = chainId.vmId;

        uint256 oldMaxDeposit =
            assets.registry[index].data[routingId][vmId][assetAddress].maxDeposits;
        assets.registry[index].data[routingId][vmId][assetAddress].maxDeposits = newMaxDeposit;
        emit MaxDepositChanged(chainId, index, oldMaxDeposit, newMaxDeposit);
    }

    function setMax1HrDeposits(
        ChainId calldata chainId,
        uint16 index,
        bytes32 assetAddress,
        uint256 newMaxDeposit
    ) external {
        if (msg.sender != riskManagerMultisig) revert NotRiskManager();
        require(index < assets.count, "!asset");

        uint64 routingId = chainId.routingId;
        uint64 vmId = chainId.vmId;

        uint256 oldMaxDeposit =
            assets.registry[index].data[routingId][vmId][assetAddress].max1hrDeposits;
        assets.registry[index].data[routingId][vmId][assetAddress].max1hrDeposits = newMaxDeposit;
        emit Max1HrDepositChanged(chainId, index, oldMaxDeposit, newMaxDeposit);
    }

    function setMinWeight(
        ChainId calldata chain,
        uint16 index,
        bytes32 assetAddress,
        uint256 newMinWeight
    ) external {
        if (msg.sender != riskManagerMultisig) revert NotRiskManager();
        require(index < assets.count, "!asset");
        uint256 oldMinWeight =
            assets.registry[index].data[chain.routingId][chain.vmId][assetAddress].minWeight;
        assets.registry[index].data[chain.routingId][chain.vmId][assetAddress].minWeight =
        newMinWeight;
        emit MinWeightChanged(chain, index, oldMinWeight, newMinWeight);
    }

    /**
     * @notice Retrieves asset data for a specific asset, chain, and address.
     * @param chainId the chain ID to query.
     * @param index The asset index to query.
     * @param assetAddress The asset address to query.
     * @return The corresponding AssetData struct.
     */
    function getAssetData(ChainId calldata chainId, uint16 index, bytes32 assetAddress)
        external
        view
        returns (AssetData memory)
    {
        return assets.registry[index].data[chainId.routingId][chainId.vmId][assetAddress];
    }

    /**
     * @notice Returns all registered asset data across all chains.
     * @return An array of AssetData structs.
     * @param start The start index (inclusive).
     * @param end The end index (not-inclusive).
     */
    function getAssets(uint16 start, uint16 end) external view returns (AssetData[] memory) {
        uint256 totalEntries = assets.totalEntries;

        // Return empty array if start >= totalEntries
        if (start >= totalEntries) {
            return new AssetData[](0);
        }

        if (end > totalEntries) {
            // casting to 'uint16' is safe because we won't ever that many assets.
            // forge-lint: disable-next-line(unsafe-typecast)
            end = uint16(totalEntries);
        }

        if (end < start) {
            return new AssetData[](0);
        }

        uint16 length = end - start;
        AssetData[] memory result = new AssetData[](length);

        uint256 r = 0;
        uint256 resIdx = 0;

        for (uint16 i = 0; i < assets.count && resIdx < length; ++i) {
            Asset storage asset = assets.registry[i];
            uint256 chainsLen = asset.chains.length;

            for (uint256 c = 0; c < chainsLen && resIdx < length; ++c) {
                if (r >= start && r < end) {
                    ChainId storage chain = asset.chains[c];
                    result[resIdx++] = asset.data[chain.routingId][chain.vmId][asset.addresses[c]];
                }

                ++r;
            }
        }

        return result;
    }

    /**
     * @notice Returns the asset index for a given chain and address.
     * @param chainId The chain ID to search.
     * @param assetAddress The asset address (as bytes32).
     * @return The index of the asset, or `type(uint32).max` if not found.
     */
    function getAssetIndex(ChainId calldata chainId, bytes32 assetAddress)
        external
        view
        returns (uint32)
    {
        uint256 stored = assetIndexLookup[chainId.routingId][chainId.vmId][assetAddress];
        if (stored == 0) {
            return type(uint32).max;
        }
        // forge-lint: disable-next-line(unsafe-typecast)
        return uint32(stored - 1);
    }

    /**
     * @notice Sets pending risk parameters for a specific asset index.
     * @param index The asset index.
     * @param parameters The risk parameters to set
     * @dev Reverts with `NotRiskManager`; Only the risk manager can set risk parameters.
     * @dev Reverts with `"!asset"` if index >= assets.count.
     */
    function setPendingRiskParameters(uint16 index, RiskParameters memory parameters) external {
        if (msg.sender != riskManagerMultisig) revert NotRiskManager();
        require(index < assets.count, "!asset");
        validateRiskParameters(parameters);
        PendingRiskParameters memory pendingParams = PendingRiskParameters({
            parameters: parameters, validAfter: block.timestamp + riskParameterChangeDelaySeconds
        });
        pendingRiskParameters[index] = pendingParams;
    }

    /**
     * @notice Applies the pending risk parameters for the specified asset if they exist.
     * @param index The asset index.
     * @dev Reverts with `"!asset"` if index >= assets.count.
     * @dev Reverts with `NoPendingRiskParameters` if there are no pending risk parameters for the specified asset
     * @dev Reverts with `TooSoon` if the pending risk parameters are not yet eligible
     */
    function applyPendingRiskParameters(uint16 index) external {
        require(index < assets.count, "!asset");
        PendingRiskParameters memory pendingParams = pendingRiskParameters[index];
        if (pendingParams.validAfter == 0) revert NoPendingRiskParameters(index);
        if (pendingParams.validAfter >= block.timestamp) {
            revert TooSoon(index, pendingParams.validAfter);
        }
        RiskParameters memory params = pendingParams.parameters;
        validateRiskParameters(params);
        riskParameters[index] = params;
        delete pendingRiskParameters[index];
    }

    function validateRiskParameters(RiskParameters memory params) public pure {
        if (params.collateralFactor > 1e2) revert InvalidCollateralFactor();
        if (params.liabilityFactor > 1e2) revert InvalidLiabilityFactor();
        if (params.maxUtilization > 1e18) revert InvalidUtilizationCap();
        if (params.maxFundingRate > 1142) revert InvalidMaxFundingRate();
        if (params.maxUtilizationRate > 1142) revert InvalidMaxUtilizationRate();

        uint256 bufferMultiple = params.bufferMultiple;
        if (bufferMultiple < 1e6 || bufferMultiple > 2e6) revert InvalidBufferMultiple();

        if (!validateStartAtZeroIsAlwaysBelowOneAndIncreases(params.interestKinks)) {
            revert InvalidInterestKinks();
        }
        if (!validateLastIsOne(params.interestKinks)) revert InvalidInterestKinks();
        if (!validateStartAtZeroIsAlwaysBelowOneAndIncreases(params.usdInterestKinks)) {
            revert InvalidUSDInterestKinks();
        }
        if (!validateLastIsOne(params.usdInterestKinks)) revert InvalidUSDInterestKinks();

        if (!validateIncreases(params.kinkInterestRates)) {
            revert InvalidRateInterestKinks();
        }
        if (!validateIncreases(params.usdKinkInterestRates)) {
            revert InvalidUSDRateInterestKinks();
        }

        if (params.initialMarginClamps.length != params.initialMarginFactors.length) {
            revert InvalidInitialMarginsConfiguration();
        }
        if (!validateStartAtZeroIsAlwaysBelowOneAndIncreases(params.initialMarginClamps)) {
            revert InvalidInitialMarginsClamps();
        }
        if (!validateIMFactors(params.initialMarginFactors)) revert InvalidInitialMarginsFactors();
    }

    /**
     * @notice Last point should be (1_000_000)
     */
    function validateLastIsOne(uint256[] memory xs) internal pure returns (bool) {
        uint256 len = xs.length;
        return len != 0 && xs[len - 1] == 1_000_000;
    }

    /**
     * @notice Validate that a series of values is increasing
     */
    function validateIncreases(uint256[] memory xs) internal pure returns (bool) {
        uint256 len = xs.length;
        uint256 prev = 0;

        for (uint256 i; i < len; ++i) {
            uint256 cur = xs[i];
            if (cur < prev) return false;
            prev = cur;
        }

        return true;
    }

    /**
     * @notice IM clamps must always increase and be <= 1 (1_000_000), and first point must be 0
     */
    function validateStartAtZeroIsAlwaysBelowOneAndIncreases(uint256[] memory xs)
        internal
        pure
        returns (bool)
    {
        uint256 len = xs.length;
        uint256 prev = 0;

        if (len == 0 || xs[0] != 0) {
            return false;
        }

        for (uint256 i; i < len; ++i) {
            uint256 cur = xs[i];
            if (cur > 1_000_000) return false;
            if (cur < prev) return false;
            prev = cur;
        }

        return true;
    }

    /**
     * @notice IM factors must always decreases and be < 1 (1_000_000)
     */
    function validateIMFactors(uint256[] memory xs) internal pure returns (bool) {
        uint256 len = xs.length;
        uint256 prev = 999_999;

        for (uint256 i; i < len; ++i) {
            uint256 cur = xs[i];
            if (cur > prev) return false;
            prev = cur;
        }

        return true;
    }

    function sumIsOne(uint256[] memory xs) internal pure returns (bool) {
        uint256 len = xs.length;
        uint256 sum;

        for (uint256 i; i < len; ++i) {
            sum += xs[i];
            if (sum > 1e6) return false;
        }

        return sum == 1e6;
    }

    /**
     * @notice Returns the full list of risk parameters for all registered assets.
     * @return An array of RiskParameters.
     * @param start The start index (inclusive).
     * @param end The end index (not inclusive).
     */
    function getRiskParameters(uint16 start, uint16 end)
        external
        view
        returns (RiskParameters[] memory)
    {
        uint16 count = uint16(assets.count);

        if (start >= count) {
            return new RiskParameters[](0);
        }

        if (end > count) {
            end = count;
        }

        if (end < start) {
            return new RiskParameters[](0);
        }

        uint256 length = end - start;
        RiskParameters[] memory result = new RiskParameters[](length);

        for (uint16 i = 0; i < length; ++i) {
            result[i] = riskParameters[start + i];
        }

        return result;
    }

    /**
     * @notice Sets the global fee account.
     * @param account The account.
     * @dev Reverts with `NotRiskManager`; Only the risk manager can set a new fee account.
     */
    function setFeeAccount(bytes32 account) external {
        if (msg.sender != riskManagerMultisig) revert NotRiskManager();
        feeAccount = account;
    }

    /**
     * @notice Get the global withdrawal delay parameters.
     */
    function getWithdrawalDelayParameters()
        external
        view
        returns (WithdrawalDelayParameters memory)
    {
        return withdrawalDelayParameters;
    }

    /**
     * @notice Queues new global withdrawal delay parameters with a time-lock.
     * @param parameters The parameters.
     * @dev Reverts with `NotRiskManager`; Only the risk manager can set new withdrawal delay parameters.
     */
    function setPendingWithdrawalDelayParameters(WithdrawalDelayParameters memory parameters)
        external
    {
        if (msg.sender != riskManagerMultisig) revert NotRiskManager();
        validateWithdrawalDelayParameters(parameters);
        pendingWithdrawalDelayParameters = PendingWithdrawalDelayParameters({
            parameters: parameters, validAfter: block.timestamp + riskParameterChangeDelaySeconds
        });
    }

    /**
     * @notice Applies the pending withdrawal delay parameters if they exist and are eligible.
     * @dev Reverts with `NoPendingWithdrawalDelayParameters` if none are queued.
     * @dev Reverts with `WithdrawalDelayParametersTooSoon` if not yet eligible.
     */
    function applyPendingWithdrawalDelayParameters() external {
        PendingWithdrawalDelayParameters memory pending = pendingWithdrawalDelayParameters;
        if (pending.validAfter == 0) revert NoPendingWithdrawalDelayParameters();
        if (pending.validAfter >= block.timestamp) {
            revert WithdrawalDelayParametersTooSoon(pending.validAfter);
        }
        WithdrawalDelayParameters memory params = pending.parameters;
        validateWithdrawalDelayParameters(params);
        withdrawalDelayParameters = params;
        delete pendingWithdrawalDelayParameters;
    }

    /**
     * @notice Validates withdrawal delay parameters.
     * @param params The parameters to validate.
     */
    function validateWithdrawalDelayParameters(WithdrawalDelayParameters memory params)
        public
        pure
    {
        if (params.minDelay > params.maxDelay) revert InvalidWithdrawalDelayBounds();
        if (params.delayClamps.length != params.delayValues.length) {
            revert InvalidWithdrawalDelayConfiguration();
        }
        if (!validateStartAtZeroIsAlwaysBelowOneAndIncreases(params.delayClamps)) {
            revert InvalidWithdrawalDelayClamps();
        }
        if (!validateIncreases(params.delayValues)) {
            revert InvalidWithdrawalDelayValues();
        }
        for (uint256 i; i < params.delayValues.length; ++i) {
            if (params.delayValues[i] < params.minDelay || params.delayValues[i] > params.maxDelay)
            {
                revert WithdrawalDelayValueOutOfBounds();
            }
        }
    }
}

