/// @notice Interface for Automata's DCAP Attestation Verifier (V3)
/// @dev Bindings for the 'AutomataDcapAttestation' contract.
///      Compatible with Automata V3 ZK Coprocessor logic.
interface IAutomataDcapAttestation {
    // Enum definition from Automata's library
    enum ZkCoProcessorType {
        RiscZero,
        Succinct // SP1
    }

    /// @notice Verifies a SNARK proof (Groth16) for a TEE Quote.
    /// @param output The Public Values (Journal) - effectively the Quote Body.
    /// @param zkvm The type of ZKVM used.
    /// @param proofBytes The actual (Groth16) proof.
    /// @return success True if valid.
    /// @return errorData Error message if failed, or empty if success.
    function verifyAndAttestWithZKProof(
        bytes calldata output,
        ZkCoProcessorType zkvm,
        bytes calldata proofBytes
    ) external returns (bool success, bytes memory errorData);
}

