        address[] memory signers,
        bytes[] memory signatures
    ) external;
    function admin() external view returns (address);
    function adminUpdateStrategies(uint256, uint256) external view returns (address);
    function appointLeader(address newLeader, address[] memory signers, bytes[] memory signatures)
        external;
    function automataVerifier() external view returns (address);
