    ) external;
    function registerAttestedKey(bytes32 newAttestedKey) external;
    function registryContract() external view returns (address);
    function resolveRestart() external;
    function restartGatheringDeadline() external view returns (uint256);
    function riskManager() external view returns (address);
    function scheduleManageProfile(
        uint256 profileId,
        MeasurementProfile memory profile,
        address[] memory signers,
        bytes[] memory signatures
    ) external returns (bytes32 opId);
    function scheduleRegistryContract(
        address newRegistry,
        address[] memory signers,
        bytes[] memory signatures
