        bytes[] memory signatures
    ) external;
    function vaults(uint256)
        external
        view
        returns (uint8 routingId, uint256 vmId, bytes32 vaultAddress, ChainConfig memory config);
    function withdraw(
        address account,
        uint256 amount,
        address[] memory signers,
        bytes[] memory signatures
    ) external;
}

