// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

interface IDepositVault {
    struct Settlement {
        address tokenOut;
        uint256 amountOut;
        address tokenIn;
        uint256 amountIn;
        bytes32 user;
        uint64 account;
        uint256 nonce;
        uint256 validUntil;
    }

    struct SettlementOrder {
        address tokenOut;
        uint256 amountOut;
        address tokenIn;
        uint256 amountIn;
        uint256 nonce;
    }

    struct SignedSettlement {
        Settlement settlement;
        bytes clearingEngineSignature;
    }

    struct SignedSettlementOrder {
        SettlementOrder settlement;
        bytes clearingEngineSignature;
    }

    struct SignerConfig {
        bytes32 key;
        uint8 keyType;
        uint8 keyPrefix;
        uint32 weight;
        uint64 expiresAtNs;
        uint64 maxSigningWindowNs;
    }

    struct Withdrawal {
        address tokenAddress;
        uint256 amount;
        uint256 nonce;
    }

    error DecimalsCallFailed();
    error DepositorNotApproved();
    error EmptyOrders();
    error Expired();
    error InsufficientAdministrators(uint256 actual, uint256 required);
    error InsufficientAmountFromExecutor(uint256 actual, uint256 required);
    error InsufficientCallbackReturnForSettlement(
        uint256 settlementIndex, uint256 actual, uint256 required
    );
    error InvalidNonce(uint256 expected, uint256 given);
    error InvalidSignature();
    error MissedQuorum(uint256 provided, uint256 required);
    error NormalizationOverflow();
    error NotAdmin();
    error NotCredentialManager();
    error NotExecutor();
    error NotOwner();
    error PayloadMismatch();
    error SettlerNotApproved();
    error TooSoon();
    error ZeroAddress();
    error ZeroAmount();
    error ZeroWithdrawalQuorum();

    event AdminAdded(address newAdmin, uint256 numAdminsAfter);
    event AdministratorSetReset();
    event CredentialManagerChanged(address oldCredentialManager, address newCredentialManager);
    event Deposited(
        bytes32 indexed user, uint256 indexed nonce, address indexed tokenAddress, uint256 amount
    );
    event DepositedWithConfig(
        bytes32 indexed user,
        uint256 indexed nonce,
        address indexed tokenAddress,
        uint256 amount,
        uint32 masterWeight,
        uint32 lowThreshold,
        uint32 mediumThreshold,
        uint32 highThreshold,
        SignerConfig[] signers,
        bytes masterConfigSignature
    );
    event Settled(
        bytes32 indexed user,
        uint64 indexed account,
        uint256 indexed nonce,
        address tokenOut,
        uint256 amountOut,
        address tokenIn,
        uint256 amountIn,
        bytes32 settler
    );
    event WithdrawalQuorumChanged(uint256 previous, uint256 current);
    event Withdrew(
        bytes32 indexed user, uint256 indexed nonce, address tokenAddress, uint256 amount
    );

    function SETTLEMENT_TYPEHASH() external view returns (bytes32);
    function addSettlerExecutor(bytes32 settler, address executor) external;
    function administrators(uint256) external view returns (address);
    function approvedSettlers(uint256) external view returns (bytes32);
    function canDeposit(address) external view returns (bool);
    function credentialManager() external view returns (address);
    function credentialManagerChangeDelayBlocks() external view returns (uint256);
    function deposit(
        bytes32 user,
        address tokenAddress,
        uint256 amount,
        uint32 masterWeight,
        uint32 lowThreshold,
        uint32 mediumThreshold,
        uint32 highThreshold,
        SignerConfig[] memory signers,
        bytes memory masterConfigSignature
    ) external;
    function deposit(bytes32 user, address tokenAddress, uint256 amount) external;
    function depositCounts(bytes32) external view returns (uint64);
    function executeAtomicSettlement(
        Settlement memory order,
        bytes32 settler,
        bytes memory data,
        bytes memory signature
    ) external;
    function executeSquashingSettlements(
        SignedSettlement[] memory requests,
        bytes[] memory data,
        bytes32 settler
    ) external;
    function getApprovedSettlers() external view returns (bytes32[] memory);
    function isAdministrator(address account) external view returns (bool);
    function lastSignatureUse() external view returns (uint256);
    function owner() external view returns (address);
    function ownerWithdrawToken(address token, address to, uint256 amount) external;
    function pendingSettlements(bytes32, uint64, uint256)
        external
        view
        returns (SettlementOrder memory settlement, address target);
    function pullBatchSettlements(
        SignedSettlementOrder[] memory orders,
        bytes32 user,
        uint64 account,
        address target,
        uint256 validUntil
    ) external;
    function pushBatchSettlements(bytes32 user, uint64 account) external;
    function removeSettler(bytes32 settler) external;
    function setAdministrators(address[] memory newAdministrators, uint256 newWithdrawalQuorum)
        external;
    function setCredentialManager(address newCredentialManager) external;
    function setDepositorStatus(address depositor, bool allowed) external;
    function setDomainSeparator(bytes32 domainSeparator) external;
    function setOwner(address newOwner) external;
    function settlementCaps(address) external view returns (uint256);
    function settlementCounts(bytes32, uint64) external view returns (uint64);
    function withdraw(
        Withdrawal memory withdrawal,
        bytes32 user,
        address target,
        uint256 validUntil,
        bytes32 epochHash,
        bytes[] memory signatures
    ) external;
    function withdrawalCounts(bytes32) external view returns (uint64);
    function withdrawalQuorum() external view returns (uint256);
}

