    error NoPendingWithdrawalDelayParameters();
    error NotAdmin();
    error NotRiskManager();
    error RiskManagerNotSet();
    error TooSoon(uint16 asset, uint256 eligibleAt);
    error WithdrawalDelayParametersTooSoon(uint256 eligibleAt);
    error WithdrawalDelayValueOutOfBounds();
    error ZeroAddress();

    event Max1HrDepositChanged(ChainId chain, uint16 index, uint256 previous, uint256 current);
    event MaxDepositChanged(ChainId chain, uint16 index, uint256 previous, uint256 current);
    event MinWeightChanged(ChainId chain, uint16 index, uint256 previous, uint256 current);

    function admin() external view returns (address);
    function applyPendingRiskParameters(uint16 index) external;
