    function riskParameters(uint16)
        external
        view
        returns (
            uint8 collateralFactor,
            uint8 liabilityFactor,
            uint256 maxCollateral,
            uint256 maxOpenInterest,
            uint256 maxSpotOpenInterest,
            uint256 maxUtilization,
            bool isolatedOnly,
            uint256 skewModifier,
            uint256 skewCliff,
            int256 baseFundingRate,
            uint256 premiumClamp,
            uint256 maxFundingRate,
            uint256 maxUtilizationRate,
            uint256 bufferMultiple
        );
    function setAdmin(address newAdmin) external;
    function setAssetData(AssetData memory data) external;
    function setFeeAccount(bytes32 account) external;
    function setMax1HrDeposits(
        ChainId memory chainId,
        uint16 index,
        bytes32 assetAddress,
        uint256 newMaxDeposit
    ) external;
    function setMaxDeposits(
        ChainId memory chainId,
        uint16 index,
        bytes32 assetAddress,
        uint256 newMaxDeposit
    ) external;
    function setMinWeight(
        ChainId memory chain,
        uint16 index,
        bytes32 assetAddress,
        uint256 newMinWeight
    ) external;
    function setPendingRiskParameters(uint16 index, RiskParameters memory parameters) external;
    function setPendingWithdrawalDelayParameters(WithdrawalDelayParameters memory parameters)
        external;
    function setRiskManagerMultisig(address multisig) external;
    function validateRiskParameters(RiskParameters memory params) external pure;
    function validateWithdrawalDelayParameters(WithdrawalDelayParameters memory params)
        external
        pure;
}

