// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import {IInbox} from "nitro-contracts/bridge/IInbox.sol";
import {IDepositVault} from "../interfaces/IDepositVault.sol";
import {IAdminUpdateStrategy} from "../interfaces/IAdminUpdateStrategy.sol";

contract ArbitrumOneAdminUpdateStrategy is IAdminUpdateStrategy {
    address public constant INBOX = 0x4Dbd4fc535Ac27206064B68FfCf827b0A60BAB3f;

    uint256 constant MAX_SUBMISSION_COST = 0.02 ether;
    uint256 constant GAS_LIMIT = 3_000_000;
    uint256 constant MAX_FEE_PER_GAS = 5 gwei;

    /// @notice Reverts if not enough value was sent to the update method.
    error InsufficientMsgValue(uint256 actual, uint256 expected);

    /**
     * @notice Updates the administrator set and withdrawal quorum on a vault via a retryable ticket.
     * @dev This function forwards a cross-chain call to the target `vault` using Arbitrum's
     *      retryable ticket mechanism. The credential manager must supply sufficient `msg.value` to cover
     *      the maximum submission cost and gas fees for execution on the destination chain.
     *
     * @param vault The address of the vault contract whose administrators will be updated.
     * @param newAdministrators The complete list of administrator addresses to set on the vault.
     * @param newWithdrawalQuorum The new quorum required for withdrawals.
     *
     * @dev Reverts with {InsufficientMsgValue} if `msg.value` is less than
     *      `MAX_SUBMISSION_COST + GAS_LIMIT * MAX_FEE_PER_GAS`.
     */
    function setAdministrators(
        address vault,
        address[] calldata newAdministrators,
        uint256 newWithdrawalQuorum
    ) external payable override {
        uint256 expectedValue =
            MAX_SUBMISSION_COST + GAS_LIMIT * MAX_FEE_PER_GAS;
        uint256 actualValue = msg.value;

        if (actualValue < expectedValue) {
            revert InsufficientMsgValue(actualValue, expectedValue);
        }

        bytes memory callData = abi.encodeWithSelector(
            IDepositVault.setAdministrators.selector, newAdministrators, newWithdrawalQuorum
        );

        IInbox inbox = IInbox(address(INBOX));
        inbox.createRetryableTicket{value: msg.value}(
            vault,
            0,
            MAX_SUBMISSION_COST,
            msg.sender,
            msg.sender,
            GAS_LIMIT,
            MAX_FEE_PER_GAS,
            callData
        );
    }
}

