// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import {IAdminUpdateStrategy} from "../interfaces/IAdminUpdateStrategy.sol";
import {IDepositVault} from "../interfaces/IDepositVault.sol";

/// Use this strategy when updating the vault on the same chain as the credential manager.
contract IntraChainAdminUpdateStrategy is IAdminUpdateStrategy {
    function setAdministrators(
        address vault,
        address[] calldata newAdministrators,
        uint256 newWithdrawalQuorum
    ) external payable {
        IDepositVault(vault).setAdministrators(newAdministrators, newWithdrawalQuorum);
    }
}

