// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import {IDepositVault} from "../interfaces/IDepositVault.sol";
import {IAdminUpdateStrategy} from "../interfaces/IAdminUpdateStrategy.sol";

interface IL1CrossDomainMessenger {
    function sendMessage(address _target, bytes calldata _message, uint32 _minGasLimit)
        external
        payable;
}

/// @notice Admin update strategy for OP Stack chains (Optimism, Base, Unichain, etc)
contract OPStackAdminUpdateStrategy is IAdminUpdateStrategy {
    /// @notice L1 CrossDomainMessenger.
    address public immutable L1_CROSS_DOMAIN_MESSENGER;

    /// @notice Conservative gas limit for L2 execution.
    uint32 public constant L2_GAS_LIMIT = 3_000_000;

    /// @notice Reverts if messenger address is zero.
    error ZeroMessengerAddress();

    constructor(address l1CrossDomainMessenger) {
        if (l1CrossDomainMessenger == address(0)) revert ZeroMessengerAddress();
        L1_CROSS_DOMAIN_MESSENGER = l1CrossDomainMessenger;
    }

    /**
     * @notice Updates the administrator set and withdrawal quorum on an OP Stack L2 vault
     * @dev Sends a cross-domain message from L1 → L2 using the OP Stack messenger
     * @dev Forwards msg.value directly to the L1 messenger
     *
     * @param vault The L2 vault address
     * @param newAdministrators The full administrator set
     * @param newWithdrawalQuorum The withdrawal quorum
     */
    function setAdministrators(
        address vault,
        address[] calldata newAdministrators,
        uint256 newWithdrawalQuorum
    ) external payable override {
        bytes memory callData = abi.encodeWithSelector(
            IDepositVault.setAdministrators.selector, newAdministrators, newWithdrawalQuorum
        );

        IL1CrossDomainMessenger(L1_CROSS_DOMAIN_MESSENGER).sendMessage{value: msg.value}(
            vault, callData, L2_GAS_LIMIT
        );
    }
}
